// ===== CHAPTER: Principles of Inheritance and Variation =====
const allQuestions = [

  // ───── TOPIC: INTRODUCTION ─────
  { id: 1, topic: "Introduction", q: "Which of the following statements about <b>J.D. Watson</b> is/are correct?<br>(i) He was born in Chicago in 1928<br>(ii) He received his B.Sc. degree in Genetics<br>(iii) His Ph.D. work was on the effect of hard X-rays on bacteriophage multiplication<br>(iv) He completed his Ph.D. from Harvard University", options: ["(i) and (iii) only", "(i), (ii) and (iii)", "(i), (iii) and (iv)", "(i), (ii), (iii) and (iv)"], correct: 0, explanation: "Watson received his B.Sc. in Zoology (not Genetics) and completed his Ph.D. from Indiana University, Bloomington (not Harvard). Statements (i) and (iii) are correct." },

  { id: 2, topic: "Introduction", q: "Francis Crick obtained his B.Sc. degree in:", options: ["Zoology", "Chemistry", "Physics", "Biology"], correct: 2, explanation: "Crick studied Physics at University College, London, and obtained his B.Sc. in 1937. A common trap is assuming he studied biology or chemistry since he is known for DNA structure." },

  { id: 3, topic: "Introduction", q: "The complementary double-helical configuration of DNA was proposed in:", options: ["Early 1950", "Late 1952", "Early March 1953", "June 1954"], correct: 2, explanation: "Watson and Crick proposed the double-helical structure of DNA in early March 1953. Their first attempt was unsatisfactory; the successful second attempt was based on more experimental evidence." },

  { id: 4, topic: "Introduction", q: "<b>Assertion (A):</b> Genetics deals with both inheritance and variation of characters.<br><b>Reason (R):</b> Inheritance is the degree by which progeny differ from their parents.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "Both A and R are false"], correct: 2, explanation: "Assertion is true — Genetics deals with inheritance AND variation. The Reason is false because Inheritance is defined as the process by which characters are passed from parent to progeny. The definition given in R is actually that of Variation." },

  { id: 5, topic: "Introduction", q: "Watson and Crick were jointly awarded the Nobel Prize in the year:", options: ["1953", "1959", "1960", "1962"], correct: 3, explanation: "Watson and Crick received the Nobel Prize in 1962. Common trap: students confuse the year of discovery (1953) with the year of Nobel Prize (1962)." },

  { id: 6, topic: "Introduction", q: "Which of the following is <b>incorrectly</b> matched?", options: ["John Collins Warren Prize — 1959", "Lasker Award — 1960", "Research Corporation Prize — 1960", "Nobel Prize — 1962"], correct: 2, explanation: "The Research Corporation Prize was awarded in 1962 (not 1960). Warren Prize — 1959, Lasker Award — 1960, and Nobel Prize — 1962 are all correctly matched." },

  { id: 7, topic: "Introduction", q: "Consider the following statements:<br>(A) Watson's early interest in bird-watching matured into a serious desire to learn genetics.<br>(B) Crick's Ph.D. thesis was entitled 'X-ray Diffraction: Polypeptides and Proteins'.<br>(C) Watson received his Ph.D. in 1954.<br>Which of the above statements is/are correct?", options: ["(A) and (B) only", "(B) and (C) only", "(A), (B) and (C)", "(A) only"], correct: 0, explanation: "Statements (A) and (B) are correct as per NCERT. Statement (C) is incorrect — Watson received his Ph.D. in 1950 (not 1954). It was Crick who completed his Ph.D. in 1954." },

  { id: 8, topic: "Introduction", q: "Humans knew that one of the causes of variation was hidden in sexual reproduction as early as:", options: ["18000–10000 B.C.", "8000–1000 B.C.", "1000–500 B.C.", "800–100 B.C."], correct: 1, explanation: "As per NCERT, humans knew from as early as 8000–1000 B.C. that sexual reproduction was one of the causes of variation." },

  { id: 9, topic: "Introduction", q: "The term 'factors' used by Mendel refers to the:", options: ["Phenotypic traits visible in organisms", "Genetic basis of inheritance", "Environmental influences on organisms", "Cytoplasmic determinants of traits"], correct: 1, explanation: "As per the passage, Mendel's 'factors' represent the genetic basis of inheritance. Understanding their structure became the focus of subsequent biological research." },

  { id: 10, topic: "Introduction", q: "Which of the following scientists is <b>NOT</b> mentioned in the NCERT text as a major contributor to molecular biology?", options: ["Nirenberg", "Khorana", "Meselson", "Benzer"], correct: 2, explanation: "The NCERT text specifically mentions Watson, Crick, Nirenberg, Khorana, Kornbergs, Benzer, Monod, and Brenner. Meselson (of Meselson-Stahl experiment) is NOT listed in this introductory list." },

  { id: 11, topic: "Introduction", q: "<b>Assertion (A):</b> Crick's friendship with Watson was a critical influence in Crick's career.<br><b>Reason (R):</b> Watson was a senior and experienced scientist when they met.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "Both A and R are false"], correct: 2, explanation: "Assertion is true — NCERT states Crick's friendship with Watson was a critical influence. Reason is false — Watson was described as 'a young man of 23' when they collaborated, not a senior scientist." },

  { id: 12, topic: "Introduction", q: "Sahiwal cows of Punjab are an example of:", options: ["Natural selection in wild populations", "Artificial selection and domestication", "Genetic drift in cattle populations", "Mutation breeding in livestock"], correct: 1, explanation: "NCERT explicitly mentions Sahiwal cows as an example of artificial selection and domestication from ancestral wild cows." },

  { id: 13, topic: "Introduction", q: "Which of the following pairs is correctly differentiated?", options: ["Inheritance – degree of differences in progeny; Variation – passing of characters", "Inheritance – passing of characters from parent to progeny; Variation – degree by which progeny differ from parents", "Inheritance – variation in gene pool; Variation – basis of heredity", "Inheritance – cause of evolution; Variation – cause of stability"], correct: 1, explanation: "As per NCERT: Inheritance = process by which characters are passed from parent to progeny (basis of heredity). Variation = degree by which progeny differ from their parents." },

  { id: 14, topic: "Introduction", q: "Watson's Ph.D. research at Indiana University was focused on:", options: ["Structure of DNA using X-ray crystallography", "X-ray diffraction of polypeptides and proteins", "Effect of hard X-rays on bacteriophage multiplication", "Genetic recombination in bacteriophages"], correct: 2, explanation: "Watson's Ph.D. (1950, Indiana University) was on the effect of hard X-rays on bacteriophage multiplication. Option B describes Crick's Ph.D. thesis. This is a common trap where students confuse Watson's and Crick's research topics." },

  { id: 15, topic: "Introduction", q: "Consider the following:<br>(i) Molecular genetics<br>(ii) Structural biology<br>(iii) Bioinformatics<br>(iv) Paleontology<br>Which of the above have enriched our understanding of the molecular basis of evolution as per NCERT?", options: ["(i), (ii) and (iii) only", "(i) and (iii) only", "(i), (ii), (iii) and (iv)", "(ii) and (iv) only"], correct: 0, explanation: "NCERT specifically mentions molecular genetics, structural biology, and bioinformatics as areas that enriched understanding of molecular basis of evolution. Paleontology is not mentioned in this context." },

  { id: 16, topic: "Introduction", q: "Crick was made a Fellow of the Royal Society (F.R.S.) in:", options: ["1953", "1954", "1959", "1962"], correct: 2, explanation: "As per NCERT, Crick was made an F.R.S. in 1959. Students often confuse this with the year of DNA discovery (1953), his Ph.D. (1954), or Nobel Prize (1962)." },

  { id: 17, topic: "Introduction", q: "Select the <b>incorrect</b> statement regarding Watson and Crick:", options: ["Watson was born in Chicago and Crick in Northampton, England", "Watson obtained B.Sc. in Zoology; Crick obtained B.Sc. in Physics", "Their first effort at solving the DNA structure was satisfactory", "Their successful DNA model was based on experimental evidence and nucleic acid literature"], correct: 2, explanation: "Their FIRST serious effort was unsatisfactory. The SECOND effort, based on more experimental evidence and better appreciation of nucleic acid literature, was successful (March 1953). This is a direct NCERT-based trap." },

  { id: 18, topic: "Introduction", q: "Which of the following correctly represents the chronological order of awards received by Watson and Crick?", options: ["Nobel Prize → Lasker Award → Warren Prize", "Warren Prize → Lasker Award → Nobel Prize", "Lasker Award → Warren Prize → Nobel Prize", "Warren Prize → Nobel Prize → Lasker Award"], correct: 1, explanation: "Chronological order: John Collins Warren Prize (1959) → Lasker Award (1960) → Research Corporation Prize & Nobel Prize (1962). So Warren Prize → Lasker Award → Nobel Prize is correct." },

  { id: 19, topic: "Introduction", q: "The 'Kornbergs' mentioned in NCERT as contributors to molecular biology refers to:", options: ["Two brothers", "Father and son", "Husband and wife", "Teacher and student"], correct: 1, explanation: "NCERT specifically mentions 'Kornbergs (father and son)' as major contributors to molecular biology. Arthur Kornberg and Roger Kornberg both made significant contributions." },

  { id: 20, topic: "Introduction", q: "<b>Assertion (A):</b> Our ancestors practised artificial selection even before understanding the scientific basis of inheritance.<br><b>Reason (R):</b> Variations naturally present in wild populations were exploited through selective breeding.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both statements are true and directly from NCERT. Ancestors exploited naturally present variations through selective breeding (R), and this was done despite having very little idea about the scientific basis of inheritance (A). R correctly explains how A was possible." },

  // ───── TOPIC: MENDEL'S LAWS OF INHERITANCE ─────
  { id: 21, topic: "Mendel's Laws of Inheritance", q: "Mendel conducted hybridisation experiments on garden peas for a period of:", options: ["Five years (1856–1861)", "Seven years (1856–1863)", "Nine years (1854–1863)", "Seven years (1857–1864)"], correct: 1, explanation: "As per NCERT, Mendel conducted hybridisation experiments on garden peas for seven years from 1856 to 1863. Students often confuse the exact start and end years — both must be remembered together." },

  { id: 22, topic: "Mendel's Laws of Inheritance", q: "Which of the following was applied for the <b>first time</b> to problems in biology during Mendel's investigations?", options: ["Microscopic analysis and cell theory", "Comparative anatomy and embryology", "Statistical analysis and mathematical logic", "Biochemical assays and chromatography"], correct: 2, explanation: "NCERT clearly states that during Mendel's investigations into inheritance patterns, it was for the first time that statistical analysis and mathematical logic were applied to problems in biology." },

  { id: 23, topic: "Mendel's Laws of Inheritance", q: "A true-breeding line is one that:<br>(i) Has undergone continuous cross-pollination<br>(ii) Shows stable trait inheritance and expression<br>(iii) Maintains stability for several generations<br>(iv) Has undergone continuous self-pollination", options: ["(i), (ii) and (iii) only", "(ii), (iii) and (iv) only", "(i), (ii), (iii) and (iv)", "(i) and (iv) only"], correct: 1, explanation: "A true-breeding line undergoes continuous SELF-pollination (not cross-pollination), shows stable trait inheritance and expression for several generations. Statement (i) is incorrect — it should be self-pollination, not cross-pollination. This is a very common NEET trap." },

  { id: 24, topic: "Mendel's Laws of Inheritance", q: "Mendel selected how many true-breeding pea plant varieties for his experiments?", options: ["7", "14", "21", "28"], correct: 1, explanation: "Mendel selected 14 true-breeding pea plant varieties, as pairs (7 pairs), which were similar except for one character with contrasting traits. Common trap: students confuse 7 characters with 7 varieties — it's actually 14 varieties forming 7 pairs." },

  { id: 25, topic: "Mendel's Laws of Inheritance", q: "<b>Assertion (A):</b> Mendel's results pointed to general rules of inheritance rather than unsubstantiated ideas.<br><b>Reason (R):</b> He used large sampling size and confirmed inferences through experiments on successive generations.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true and directly from NCERT. Large sampling size gave credibility, and confirmation through successive generations proved generality — both factors (R) explain why results were general rules and not unsubstantiated ideas (A)." },

  { id: 26, topic: "Mendel's Laws of Inheritance", q: "Which of the following is the correct contrasting trait pair for <b>pod colour</b> as studied by Mendel?", options: ["Yellow or green", "Green or yellow", "Inflated or constricted", "Round or wrinkled"], correct: 1, explanation: "Pod colour contrasting traits are Green/Yellow (as per NCERT table). Option A (Yellow/Green) refers to seed colour, not pod colour. Option C is pod shape and Option D is seed shape. Students frequently interchange pod colour and seed colour — a classic NEET trap." },

  { id: 27, topic: "Mendel's Laws of Inheritance", q: "Which of the following contrasting trait pairs is <b>incorrectly</b> matched with its character?", options: ["Stem height — Tall/Dwarf", "Flower colour — Violet/White", "Flower position — Axial/Lateral", "Pod shape — Inflated/Constricted"], correct: 2, explanation: "Flower position contrasting traits are Axial/Terminal (not Axial/Lateral). All other options are correctly matched as per NCERT. 'Lateral' is a distractor — the correct term is 'Terminal'." },

  { id: 28, topic: "Mendel's Laws of Inheritance", q: "Consider the following statements about Mendel's experiments:<br>(A) He used artificial pollination/cross-pollination experiments<br>(B) He worked with self-pollinating plants<br>(C) Characters were manifested as three opposing traits<br>(D) He investigated characters in the garden pea plant<br>Select the <b>correct</b> statements:", options: ["(A), (B) and (D) only", "(A), (C) and (D) only", "(B) and (D) only", "(A), (B), (C) and (D)"], correct: 0, explanation: "Statement (C) is incorrect — characters were manifested as TWO opposing traits (not three), e.g., tall or dwarf. All other statements (A, B, D) are correct as per NCERT." },

  { id: 29, topic: "Mendel's Laws of Inheritance", q: "The large sampling size in Mendel's experiments contributed to:", options: ["Faster completion of experiments", "Discovery of new plant species", "Greater credibility to the data collected", "Elimination of all environmental factors"], correct: 2, explanation: "NCERT states: 'His experiments had a large sampling size, which gave greater credibility to the data that he collected.' It did not eliminate environmental factors or speed up experiments." },

  { id: 30, topic: "Mendel's Laws of Inheritance", q: "How many characters with contrasting traits did Mendel study in garden pea?", options: ["5", "6", "7", "14"], correct: 2, explanation: "Mendel studied 7 characters with contrasting traits: stem height, flower colour, flower position, pod shape, pod colour, seed shape, and seed colour. He selected 14 varieties (7 pairs). Trap: 14 is the number of varieties, not characters." },

  { id: 31, topic: "Mendel's Laws of Inheritance", q: "<b>Assertion (A):</b> Mendel's 14 true-breeding pea plant varieties were selected as pairs.<br><b>Reason (R):</b> Each pair was similar except for one character with contrasting traits.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both statements are directly from NCERT. The 14 varieties were selected 'as pairs which were similar except for one character with contrasting traits.' R correctly explains why they were chosen as pairs (A)." },

  { id: 32, topic: "Mendel's Laws of Inheritance", q: "Which of the following is <b>NOT</b> a contrasting trait pair studied by Mendel?", options: ["Violet and white flower colour", "Axial and terminal flower position", "Green and yellow stem colour", "Round and wrinkled seed shape"], correct: 2, explanation: "Green and yellow stem colour was NOT studied by Mendel. Green/Yellow was a contrasting pair for pod colour (not stem colour). Stem height (Tall/Dwarf) was the character related to stem. This is a carefully designed distractor." },

  { id: 33, topic: "Mendel's Laws of Inheritance", q: "Match the following characters with their correct contrasting traits:<br>(a) Pod shape — (i) Yellow/Green<br>(b) Seed colour — (ii) Inflated/Constricted<br>(c) Flower position — (iii) Violet/White<br>(d) Flower colour — (iv) Axial/Terminal", options: ["a–ii, b–i, c–iv, d–iii", "a–i, b–ii, c–iii, d–iv", "a–ii, b–iii, c–iv, d–i", "a–iv, b–i, c–ii, d–iii"], correct: 0, explanation: "Pod shape = Inflated/Constricted (a–ii), Seed colour = Yellow/Green (b–i), Flower position = Axial/Terminal (c–iv), Flower colour = Violet/White (d–iii). Students often confuse pod colour (Green/Yellow) with seed colour (Yellow/Green)." },

  { id: 34, topic: "Mendel's Laws of Inheritance", q: "The credibility of Mendel's experiments was enhanced by:<br>(i) Large sampling size<br>(ii) Use of microscopy<br>(iii) Confirmation through successive generations<br>(iv) Application of statistical analysis", options: ["(i) and (ii) only", "(i), (ii) and (iii)", "(i), (iii) and (iv) only", "(i), (ii), (iii) and (iv)"], correct: 2, explanation: "NCERT mentions large sampling size, confirmation through successive generations, and use of statistical analysis/mathematical logic. Microscopy is NOT mentioned as a factor enhancing credibility of Mendel's experiments." },

  { id: 35, topic: "Mendel's Laws of Inheritance", q: "Select the correct statement regarding Mendel's work:", options: ["Mendel proposed laws of inheritance in wild organisms only", "Mendel's framework of rules was never expanded by later scientists", "Mendel set up a basic framework of rules that was expanded by later scientists", "Mendel studied characters that showed multiple opposing traits"], correct: 2, explanation: "NCERT states Mendel set up 'a basic framework of rules governing inheritance, which was expanded on by later scientists to account for all the diverse natural observations.' He proposed laws for living organisms (not just wild), and characters had TWO (not multiple) opposing traits." },

  { id: 36, topic: "Mendel's Laws of Inheritance", q: "Inflated and constricted are contrasting traits for which character in pea?", options: ["Seed shape", "Pod colour", "Pod shape", "Stem height"], correct: 2, explanation: "Inflated (full) and constricted are contrasting traits for pod shape. Seed shape has round/wrinkled. This is directly from the NCERT table of contrasting traits." },

  { id: 37, topic: "Mendel's Laws of Inheritance", q: "<b>Assertion (A):</b> True-breeding lines show stable trait inheritance for several generations.<br><b>Reason (R):</b> True-breeding lines are obtained through continuous cross-pollination with different varieties.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 2, explanation: "Assertion is true — true-breeding lines show stable trait inheritance for several generations. Reason is false — true-breeding lines are obtained through continuous SELF-pollination (not cross-pollination with different varieties). This is a classic NEET conceptual trap." },

  { id: 38, topic: "Mendel's Laws of Inheritance", q: "Which of the following characters studied by Mendel relates to <b>reproductive parts</b> of the pea plant?<br>(i) Flower colour<br>(ii) Flower position<br>(iii) Pod shape<br>(iv) Stem height", options: ["(i) and (ii) only", "(i), (ii) and (iii) only", "(iii) and (iv) only", "(i), (ii), (iii) and (iv)"], correct: 1, explanation: "Flower colour, flower position, and pod shape all relate to reproductive parts (flowers and fruits/pods are reproductive structures). Stem height relates to the vegetative part. Pod (fruit) develops from the ovary after fertilization, hence reproductive." },

  { id: 39, topic: "Mendel's Laws of Inheritance", q: "Consider the following pairs of contrasting traits:<br>(A) Seed colour – Yellow/Green<br>(B) Pod colour – Green/Yellow<br>(C) Seed shape – Smooth/Wrinkled<br>(D) Pod shape – Inflated/Deflated<br>Which of the above are correctly stated as per NCERT?", options: ["(A) and (B) only", "(A), (B) and (C) only", "(C) and (D) only", "(A), (B), (C) and (D)"], correct: 1, explanation: "Seed colour: Yellow/Green ✓; Pod colour: Green/Yellow ✓; Seed shape is described as both 'Round/Wrinkled' and 'Smooth/Wrinkled' in NCERT text (smooth or wrinkled seeds mentioned) ✓. Pod shape is Inflated/Constricted (NOT Deflated) ✗. Hence A, B, and C are correct." },

  { id: 40, topic: "Mendel's Laws of Inheritance", q: "Mendel proposed the laws of inheritance based on his experiments on:", options: ["Antirrhinum majus (Snapdragon)", "Pisum sativum (Garden pea)", "Lathyrus odoratus (Sweet pea)", "Mirabilis jalapa (Four o'clock plant)"], correct: 1, explanation: "Mendel conducted his hybridisation experiments on garden pea (Pisum sativum). Snapdragon and Four o'clock plant are examples used for incomplete dominance. Sweet pea was used by Bateson and Punnett." },

  { id: 41, topic: "Mendel's Laws of Inheritance", q: "Which of the following statements is <b>incorrect</b> about Mendel's approach?", options: ["He applied statistical analysis to biological problems", "His experiments had a large sampling size", "He studied characters with multiple allelic forms in pea", "He confirmed inferences through experiments on successive generations"], correct: 2, explanation: "Mendel studied characters manifested as TWO opposing traits (e.g., tall or dwarf), not multiple allelic forms. The concept of multiple alleles was not part of Mendel's original experiments. All other statements are correct per NCERT." },

  { id: 42, topic: "Mendel's Laws of Inheritance", q: "The contrasting trait for <b>axial</b> flower position in Mendel's pea experiment is:", options: ["Lateral", "Basal", "Terminal", "Apical"], correct: 2, explanation: "As per the NCERT table, the contrasting traits for flower position are Axial and Terminal. Lateral, basal, and apical are distractors not used in Mendel's experiments." },

  { id: 43, topic: "Mendel's Laws of Inheritance", q: "The 14 true-breeding varieties selected by Mendel differed in:", options: ["Multiple characters simultaneously", "One character with contrasting traits per pair", "Quantitative characters only", "Chromosomal number"], correct: 1, explanation: "NCERT states: 'Mendel selected 14 true-breeding pea plant varieties, as pairs which were similar except for ONE character with contrasting traits.' Each pair differed in only one character — this is the basis of monohybrid analysis." },

  { id: 44, topic: "Mendel's Laws of Inheritance", q: "<b>Assertion (A):</b> Mendel's basic framework of inheritance rules needed expansion by later scientists.<br><b>Reason (R):</b> Natural observations show diversity and complexity that Mendel's initial rules alone could not fully account for.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "Both A and R are false"], correct: 0, explanation: "Both are true and from NCERT. Mendel set up 'a basic framework of rules governing inheritance, which was expanded on by later scientists to account for all the diverse natural observations and the complexity inherent in them.' R explains why expansion was needed (A)." },

  { id: 45, topic: "Mendel's Laws of Inheritance", q: "Which of the following characters studied by Mendel pertains to <b>seeds</b>?<br>(i) Seed shape<br>(ii) Seed colour<br>(iii) Pod shape<br>(iv) Pod colour", options: ["(i) and (ii) only", "(iii) and (iv) only", "(i), (ii), (iii) and (iv)", "(i), (ii) and (iii) only"], correct: 0, explanation: "Only Seed shape (Round/Wrinkled) and Seed colour (Yellow/Green) pertain to seeds. Pod shape (Inflated/Constricted) and Pod colour (Green/Yellow) pertain to the fruit (pod), not the seed. This distinction is a frequent NEET trap." },

  // ───── TOPIC: INHERITANCE OF ONE GENE ─────
  { id: 46, topic: "Inheritance of One Gene", q: "In Mendel's monohybrid cross between tall (TT) and dwarf (tt) pea plants, the F<sub>1</sub> generation showed:", options: ["All dwarf plants", "All tall plants", "Both tall and dwarf in 3:1 ratio", "Both tall and dwarf in 1:1 ratio"], correct: 1, explanation: "All F1 progeny from the cross TT × tt are Tt (heterozygous). Since T (tall) is dominant over t (dwarf), all F1 plants are tall. The 3:1 ratio appears only in the F2 generation after self-pollination of F1." },

  { id: 47, topic: "Inheritance of One Gene", q: "The phenotypic and genotypic ratios of F<sub>2</sub> generation in a Mendelian monohybrid cross are respectively:", options: ["1:2:1 and 3:1", "3:1 and 1:2:1", "3:1 and 3:1", "1:2:1 and 1:2:1"], correct: 1, explanation: "In F2: Phenotypic ratio = 3 (dominant) : 1 (recessive) = 3:1. Genotypic ratio = 1TT : 2Tt : 1tt = 1:2:1. A very common trap is reversing these two ratios." },

  { id: 48, topic: "Inheritance of One Gene", q: "Which of the following correctly defines <b>alleles</b> as per NCERT?", options: ["Genes present on different chromosomes coding for different traits", "Slightly different forms of the same gene that code for a pair of contrasting traits", "Identical copies of a gene on homologous chromosomes", "Non-heritable variations in gene expression"], correct: 1, explanation: "NCERT states: 'Genes which code for a pair of contrasting traits are known as alleles, i.e., they are slightly different forms of the same gene.' Option C describes homozygous condition, not alleles in general." },

  { id: 49, topic: "Inheritance of One Gene", q: "<b>Assertion (A):</b> The contrasting traits in Mendel's F<sub>1</sub> and F<sub>2</sub> generations did not show any blending.<br><b>Reason (R):</b> Alleles segregate during gamete formation and are transmitted unchanged to the next generation.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both A and R are true. NCERT explicitly states 'the contrasting traits did not show any blending at either F1 or F2 stage.' This is because alleles (factors) segregate cleanly during meiosis and are passed unchanged — which is why blending doesn't occur. R correctly explains A." },

  { id: 50, topic: "Inheritance of One Gene", q: "In Mendel's monohybrid cross, the proportion of dwarf plants in the F<sub>2</sub> generation was:", options: ["1/2", "3/4", "1/3", "1/4"], correct: 3, explanation: "In F2 of a monohybrid cross, ¾ plants are tall and ¼ are dwarf. The ¼ dwarfs are homozygous recessive (tt). Common trap: 1/3 is the ratio of dwarfs among the genotypes (tt out of TT:Tt:tt = 1:2:1), but phenotypically dwarfs are ¼." },

  { id: 51, topic: "Inheritance of One Gene", q: "The Punnett Square was developed by:", options: ["Gregor Mendel", "T.H. Morgan", "Reginald C. Punnett", "Hugo de Vries"], correct: 2, explanation: "NCERT specifically states that the Punnett Square was developed by a British geneticist, Reginald C. Punnett. It is a graphical representation to calculate probability of all possible genotypes in a genetic cross." },

  { id: 52, topic: "Inheritance of One Gene", q: "Consider the following statements about a <b>test cross</b>:<br>(i) It involves crossing an organism with a dominant phenotype with the recessive parent<br>(ii) It is used to determine the genotype of an organism showing dominant phenotype<br>(iii) It involves self-crossing of F<sub>1</sub> hybrid<br>(iv) It was first proposed by Mendel", options: ["(i), (ii) and (iii) only", "(i), (ii) and (iv) only", "(ii) and (iii) only", "(i), (ii), (iii) and (iv)"], correct: 1, explanation: "Statement (iii) is incorrect — test cross involves crossing with the RECESSIVE PARENT, not self-crossing. Self-crossing of F1 gives the F2 generation. Test cross is different from self-pollination. Statements (i), (ii) and (iv) are correct per NCERT." },

  { id: 53, topic: "Inheritance of One Gene", q: "In a monohybrid cross, the F<sub>2</sub> genotypic ratio 1:2:1 can be mathematically represented as:", options: ["(½T + ½t)³", "(¼T + ¾t)²", "(½T + ½t)²", "(T + t)²"], correct: 2, explanation: "NCERT states the binomial expression: (½T + ½t)² = (½T + ½t) × (½T + ½t) = ¼TT + ½Tt + ¼tt. This represents the gametes bearing genes T or t in equal frequency of ½." },

  { id: 54, topic: "Inheritance of One Gene", q: "Why does Mendel recommend using <b>T</b> for tall and <b>t</b> for dwarf rather than T and d?", options: ["T and d represent linked genes", "Capital and lowercase of the same letter helps remember they are alleles of the same gene", "T and d indicate genes on different chromosomes", "T and d cannot be used in Punnett squares"], correct: 1, explanation: "NCERT explains: 'Do not use T for tall and d for dwarf because you will find it difficult to remember whether T and d are alleles of the same gene/character or not.' Using capital and lowercase of the SAME alphabet logically represents dominance-recessiveness of the SAME gene." },

  { id: 55, topic: "Inheritance of One Gene", q: "<b>Assertion (A):</b> It is not possible to distinguish between TT and Tt plants by just looking at their phenotype.<br><b>Reason (R):</b> The dominant allele masks the expression of the recessive allele in heterozygous condition.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states 'Externally it is not possible to distinguish between the plants with the genotypes TT and Tt.' This is because the dominant allele T masks the recessive allele t in Tt, making it phenotypically identical to TT. R correctly explains A." },

  { id: 56, topic: "Inheritance of One Gene", q: "When Mendel self-pollinated dwarf F<sub>2</sub> plants, the F<sub>3</sub> and F<sub>4</sub> generations showed:", options: ["Both tall and dwarf in 3:1 ratio", "Both tall and dwarf in 1:2:1 ratio", "Only dwarf plants", "Only tall plants"], correct: 2, explanation: "Dwarf F2 plants are homozygous recessive (tt). Self-pollination of tt × tt gives only tt offspring. NCERT states: 'Mendel self-pollinated the F2 plants and found that dwarf F2 plants continued to generate dwarf plants in F3 and F4 generations.'" },

  { id: 57, topic: "Inheritance of One Gene", q: "The segregation of alleles occurs during:", options: ["Mitosis", "Fertilisation", "Meiosis", "Vegetative growth"], correct: 2, explanation: "NCERT states: 'when the tall and dwarf plant produce gametes, by the process of meiosis, the alleles of the parental pair separate or segregate from each other.' Segregation occurs during meiosis (gamete formation), NOT mitosis or fertilisation." },

  { id: 58, topic: "Inheritance of One Gene", q: "Which of the following is the <b>correct</b> definition of a gene as given in NCERT?", options: ["A segment of DNA that codes for tRNA only", "The unit of inheritance that contains information to express a particular trait", "A protein molecule responsible for phenotype", "A chromosome segment that undergoes crossing over"], correct: 1, explanation: "NCERT defines: 'Genes are the units of inheritance. They contain the information that is required to express a particular trait in an organism.' Genes are not proteins, and their definition extends beyond coding for tRNA." },

  { id: 59, topic: "Inheritance of One Gene", q: "A plant heterozygous for a single character is called:", options: ["Dihybrid", "Monohybrid", "Polyhybrid", "Homozygote"], correct: 1, explanation: "NCERT states: 'Since the Tt plant is heterozygous for genes controlling one character (height), it is a monohybrid.' A dihybrid is heterozygous for TWO characters. The cross TT × tt is a monohybrid cross." },

  { id: 60, topic: "Inheritance of One Gene", q: "In a test cross, a tall plant from F<sub>2</sub> generation with <b>genotype TT</b> is crossed with a dwarf plant. The offspring will be:", options: ["All tall (Tt)", "All dwarf (tt)", "3 tall : 1 dwarf", "1 tall : 1 dwarf"], correct: 0, explanation: "TT × tt → all Tt (heterozygous tall). If the test cross gives ALL tall offspring, the parent was homozygous dominant (TT). If it gives 1:1 tall:dwarf, the parent was heterozygous (Tt). This is the diagnostic power of a test cross." },

  { id: 61, topic: "Inheritance of One Gene", q: "In a test cross, a tall plant from F<sub>2</sub> generation with <b>genotype Tt</b> is crossed with a dwarf plant. The phenotypic ratio of offspring will be:", options: ["All tall", "3 tall : 1 dwarf", "1 tall : 1 dwarf", "All dwarf"], correct: 2, explanation: "Tt × tt → ½ Tt (tall) : ½ tt (dwarf) = 1:1 ratio. This confirms the parent was heterozygous. If the ratio were all tall, the parent would have been TT. The test cross distinguishes TT from Tt." },

  { id: 62, topic: "Inheritance of One Gene", q: "Consider the following statements:<br>(A) In Mendel's monohybrid cross, ¾ of F<sub>2</sub> tall plants are TT<br>(B) In F<sub>2</sub>, ½ of the total plants are heterozygous Tt<br>(C) Genotypically, ¼ of F<sub>2</sub> plants are TT<br>(D) All F<sub>2</sub> dwarf plants are homozygous<br>Which of the above are correct?", options: ["(A), (B) and (C) only", "(B), (C) and (D) only", "(A) and (D) only", "(A), (B), (C) and (D)"], correct: 1, explanation: "Statement (A) is INCORRECT — ¾ of F2 plants are TALL (phenotypically), but NOT all are TT. Among ¾ tall plants, only ¼ of total are TT and ½ are Tt. Statements B (½ Tt), C (¼ TT), and D (all dwarfs are homozygous tt) are correct." },

  { id: 63, topic: "Inheritance of One Gene", q: "<b>Assertion (A):</b> The F<sub>1</sub> generation of a monohybrid cross produces gametes T and t in equal proportions.<br><b>Reason (R):</b> Segregation of alleles is a random process with a 50 per cent chance of a gamete containing either allele.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both A and R are true and from NCERT. The F1 Tt produces gametes T and t in equal proportion. NCERT states: 'This segregation of alleles is a random process and so there is a 50 per cent chance of a gamete containing either allele.' R correctly explains why equal gametes are formed." },

  { id: 64, topic: "Inheritance of One Gene", q: "In Mendel's experiments, the trait seen in the F<sub>1</sub> generation but <b>not</b> in the other parent is called:", options: ["Recessive trait", "Co-dominant trait", "Dominant trait", "Epistatic trait"], correct: 2, explanation: "NCERT states: 'the F1 always resembled either one of the parents.' The trait expressed in F1 heterozygotes is the dominant trait. The trait NOT seen in F1 but reappearing in F2 is the recessive trait." },

  { id: 65, topic: "Inheritance of One Gene", q: "Which of the following is <b>incorrect</b> about Mendel's monohybrid cross?", options: ["F1 offspring showed traits of only one parent", "F2 showed both parental traits in 3:1 ratio", "F1 showed blending of parental traits", "The recessive trait reappeared in F2 without any blending"], correct: 2, explanation: "NCERT explicitly states: 'The tall and dwarf traits were identical to their parental type and did not show any blending' and 'The contrasting traits did not show any blending at either F1 or F2 stage.' Option C is incorrect — there was NO blending at any stage." },

  { id: 66, topic: "Inheritance of One Gene", q: "The Punnett Square is a:", options: ["Statistical table for chi-square analysis", "Graphical representation to calculate the probability of all possible genotypes of offspring in a genetic cross", "Diagram showing the physical positions of genes on chromosomes", "Mathematical formula for predicting mutation rates"], correct: 1, explanation: "NCERT defines: 'It is a graphical representation to calculate the probability of all possible genotypes of offspring in a genetic cross.' The possible gametes are written on two sides (top row and left columns) and combinations appear in boxes." },

  { id: 67, topic: "Inheritance of One Gene", q: "A true-breeding tall pea plant has the genotype:", options: ["Tt", "tt", "TT", "T"], correct: 2, explanation: "NCERT states: 'Mendel also proposed that in a true breeding, tall or dwarf pea variety the allelic pair of genes for height are identical or homozygous, TT and tt, respectively.' True-breeding tall = TT (homozygous dominant)." },

  { id: 68, topic: "Inheritance of One Gene", q: "Among the F<sub>2</sub> tall plants obtained from a monohybrid cross, what fraction would be <b>heterozygous</b>?", options: ["1/4", "1/2", "2/3", "3/4"], correct: 2, explanation: "In F2: ¼ TT + ½ Tt + ¼ tt. Among tall plants (¾ total), TT = ¼ and Tt = ½. So fraction of heterozygous among tall = (½)/(¾) = 2/3. This is a very frequently asked NEET trap — students confuse ½ (of total) with the fraction among tall plants (2/3)." },

  { id: 69, topic: "Inheritance of One Gene", q: "Select the <b>incorrect</b> statement about the Law of Dominance:", options: ["In a pair of dissimilar factors, one dominates the other", "The dominant factor is expressed in the F1 heterozygote", "The recessive factor blends with the dominant factor in F1", "The dominant allele is represented by a capital letter"], correct: 2, explanation: "NCERT clearly states there is NO blending at either F1 or F2 stage. The dominant allele completely masks the recessive allele in heterozygous condition — it does NOT blend with it. All other statements are correct." },

  { id: 70, topic: "Inheritance of One Gene", q: "If a tall F<sub>2</sub> plant is self-pollinated, which of the following results is <b>NOT</b> possible?", options: ["All tall offspring", "3 tall : 1 dwarf offspring", "All dwarf offspring", "Both (A) and (B) are possible"], correct: 2, explanation: "A tall F2 plant can be either TT or Tt. If TT is self-pollinated → all tall. If Tt is self-pollinated → 3 tall : 1 dwarf. It CANNOT produce all dwarf offspring because that requires tt × tt genotype, and the parent is phenotypically tall." },

  { id: 71, topic: "Inheritance of One Gene", q: "Consider the following:<br>(i) Genotype refers to the genetic composition (e.g., TT, Tt, tt)<br>(ii) Phenotype refers to the observable trait (e.g., tall, dwarf)<br>(iii) A plant with genotype Tt shows intermediate phenotype<br>(iv) Homozygous individuals have identical allelic pairs", options: ["(i), (ii) and (iv) only", "(i), (ii), (iii) and (iv)", "(i) and (ii) only", "(iii) and (iv) only"], correct: 0, explanation: "Statement (iii) is INCORRECT — Tt does NOT show an intermediate phenotype. NCERT states the F1 heterozygote Tt is 'exactly like the TT parent in appearance.' There is no blending or intermediate expression. Statements (i), (ii), and (iv) are correct." },

  { id: 72, topic: "Inheritance of One Gene", q: "<b>Assertion (A):</b> A test cross involves crossing the organism with the recessive parent, not self-crossing.<br><b>Reason (R):</b> Self-crossing of F<sub>1</sub> produces the F<sub>2</sub> generation, not a test cross progeny.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both A and R are true. NCERT defines test cross as crossing 'with the recessive parent instead of self-crossing.' Self-crossing of F1 generates F2 (3:1 ratio), which is different from a test cross (which gives 1:1 if heterozygous). R explains why test cross is distinct from selfing." },

  { id: 73, topic: "Inheritance of One Gene", q: "In the context of Mendel's laws, the <b>First Law</b> and <b>Second Law</b> are respectively:", options: ["Law of Segregation and Law of Independent Assortment", "Law of Dominance and Law of Segregation", "Law of Segregation and Law of Dominance", "Law of Independent Assortment and Law of Dominance"], correct: 1, explanation: "NCERT clearly states: 'the First Law or Law of Dominance and the Second Law or Law of Segregation.' Students commonly confuse the numbering — Law of Dominance is First, Law of Segregation is Second." },

  { id: 74, topic: "Inheritance of One Gene", q: "Mendel proposed that 'factors' are passed from parent to offspring through:", options: ["Blood", "Cytoplasm", "Gametes", "Somatic cells"], correct: 2, explanation: "NCERT states: 'Mendel proposed that something was being stably passed down, unchanged, from parent to offspring through the gametes, over successive generations.' Not through blood (pangenesis theory was rejected) or somatic cells." },

  { id: 75, topic: "Inheritance of One Gene", q: "Which of the following crosses will help determine whether a violet-flowered pea plant (V–) is homozygous or heterozygous?", options: ["Crossing with another violet-flowered plant", "Self-pollination and observing F2 ratio", "Crossing with a white-flowered plant (vv)", "Both (B) and (C)"], correct: 3, explanation: "Both self-pollination (observing 3:1 in F2 if heterozygous, or all violet if homozygous) and test cross with recessive parent vv (observing 1:1 if Vv, or all violet if VV) can determine genotype. NCERT specifically mentions test cross for this purpose, but self-pollination also works. Hence both B and C are correct methods." },

  // ───── TOPIC: LAW OF DOMINANCE ─────
  { id: 76, topic: "Law of Dominance", q: "Which of the following is <b>NOT</b> a postulate of Mendel's Law of Dominance?", options: ["Characters are controlled by discrete units called factors", "Factors occur in pairs", "In a dissimilar pair, one factor dominates the other", "Factors of a pair segregate during gamete formation"], correct: 3, explanation: "The Law of Dominance has three postulates: (i) factors are discrete units, (ii) factors occur in pairs, (iii) one factor dominates the other in a dissimilar pair. Segregation during gamete formation is part of the Law of Segregation, NOT the Law of Dominance." },

  { id: 77, topic: "Law of Dominance", q: "The Law of Dominance explains:<br>(i) Expression of only one parental character in F<sub>1</sub><br>(ii) Expression of both characters in F<sub>2</sub><br>(iii) The 3:1 ratio in F<sub>2</sub><br>(iv) Blending of traits in F<sub>1</sub>", options: ["(i), (ii) and (iii) only", "(i) and (iii) only", "(i), (ii), (iii) and (iv)", "(ii) and (iv) only"], correct: 0, explanation: "NCERT states the Law of Dominance explains: expression of only one character in F1, expression of both in F2, and the 3:1 ratio at F2. There is NO blending of traits — statement (iv) is incorrect." },

  { id: 78, topic: "Law of Dominance", q: "According to the Law of Dominance, in a dissimilar pair of factors:", options: ["Both factors are equally expressed", "Both factors blend to produce an intermediate trait", "One member dominates the other", "Neither factor is expressed"], correct: 2, explanation: "The third postulate of the Law of Dominance states: 'In a dissimilar pair of factors one member of the pair dominates (dominant) the other (recessive).' There is no equal expression or blending." },

  { id: 79, topic: "Law of Dominance", q: "<b>Assertion (A):</b> The Law of Dominance explains the 3:1 phenotypic ratio in F<sub>2</sub>.<br><b>Reason (R):</b> The dominant factor masks the expression of the recessive factor in heterozygous F<sub>1</sub>, and both are expressed separately in F<sub>2</sub>.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. The 3:1 ratio arises because ¾ show the dominant phenotype (TT + Tt both appear tall due to dominance) and ¼ show recessive (tt). This happens because dominance masks recessive in F1, and after segregation, both traits reappear in F2. R correctly explains A." },

  { id: 80, topic: "Law of Dominance", q: "Which of the following correctly lists <b>all three</b> postulates of the Law of Dominance?", options: ["Factors are discrete, factors are linked, one dominates the other", "Factors occur in pairs, one dominates the other, factors blend in F1", "Factors are discrete units, factors occur in pairs, one dominates the other in a dissimilar pair", "Factors occur in pairs, factors segregate, one dominates the other"], correct: 2, explanation: "The three postulates are: (i) Characters controlled by discrete units (factors), (ii) Factors occur in pairs, (iii) In a dissimilar pair, one dominates (dominant) the other (recessive). Options A, B, D include incorrect elements like linkage, blending, or segregation." },

  { id: 81, topic: "Law of Dominance", q: "Consider the following:<br>(A) Law of Dominance explains why only one parental character appears in F<sub>1</sub><br>(B) Law of Dominance explains the 1:2:1 genotypic ratio in F<sub>2</sub><br>(C) Law of Dominance explains the 3:1 phenotypic ratio in F<sub>2</sub><br>(D) Law of Dominance explains why both characters appear in F<sub>2</sub><br>Which statements are correct as per NCERT?", options: ["(A), (B), (C) and (D)", "(A), (C) and (D) only", "(A) and (C) only", "(B) and (D) only"], correct: 1, explanation: "NCERT states the Law of Dominance explains: (i) expression of only one parental character in F1 (A), (ii) expression of both in F2 (D), and (iii) the 3:1 ratio at F2 (C). The 1:2:1 genotypic ratio (B) is explained by the Law of Segregation, not Dominance." },

  // ───── TOPIC: LAW OF SEGREGATION ─────
  { id: 82, topic: "Law of Segregation", q: "The Law of Segregation is based on the fact that:", options: ["Alleles blend during gamete formation", "Alleles do not show any blending and both characters are recovered in F2", "Only dominant alleles are transmitted to gametes", "Both alleles are transmitted together into a single gamete"], correct: 1, explanation: "NCERT states: 'This law is based on the fact that the alleles do not show any blending and that both the characters are recovered as such in the F2 generation though one of these is not seen at the F1 stage.' Alleles segregate, they don't blend." },

  { id: 83, topic: "Law of Segregation", q: "According to the Law of Segregation, during gamete formation:", options: ["Both alleles of a pair move into the same gamete", "Alleles of a pair segregate so that a gamete receives only one of the two factors", "Only the dominant allele is passed to the gamete", "Alleles fuse to form a new combined factor in the gamete"], correct: 1, explanation: "NCERT clearly states: 'the factors or alleles of a pair segregate from each other such that a gamete receives only one of the two factors.' Each gamete gets only ONE allele from each pair." },

  { id: 84, topic: "Law of Segregation", q: "A homozygous parent (TT) produces:", options: ["Two kinds of gametes (T and t) in equal proportion", "All similar gametes containing allele T", "Gametes with both alleles T and T together", "No gametes due to homozygous condition"], correct: 1, explanation: "NCERT states: 'a homozygous parent produces all gametes that are similar.' TT produces only T gametes. A heterozygous parent (Tt) produces two kinds of gametes (T and t) in equal proportion." },

  { id: 85, topic: "Law of Segregation", q: "<b>Assertion (A):</b> A heterozygous parent produces two kinds of gametes each having one allele with equal proportion.<br><b>Reason (R):</b> During gamete formation, alleles of a pair segregate from each other.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both statements are true and directly from NCERT. A heterozygous Tt parent produces T and t gametes in equal proportion (A) BECAUSE alleles segregate during gamete formation (R). R is the mechanistic basis for A." },

  { id: 86, topic: "Law of Segregation", q: "Select the <b>incorrect</b> statement regarding the Law of Segregation:", options: ["Both characters are recovered as such in F2 generation", "One of the characters is not seen at F1 stage", "Alleles show blending in F1 but separate in F2", "A gamete receives only one of the two factors"], correct: 2, explanation: "NCERT explicitly states 'alleles do not show any blending.' There is no blending at ANY stage — neither F1 nor F2. The recessive allele is masked in F1 (not blended) and reappears unchanged in F2." },

  { id: 87, topic: "Law of Segregation", q: "The Law of Segregation is also known as:", options: ["Law of Purity of Gametes", "Law of Independent Assortment", "Law of Dominance", "Law of Unit Characters"], correct: 0, explanation: "The Law of Segregation is also called the Law of Purity of Gametes because each gamete is pure, receiving only one allele from each pair. This ensures gametes carry only one factor, not a blend." },

  { id: 88, topic: "Law of Segregation", q: "<b>Assertion (A):</b> The recessive parental trait appears unchanged in F<sub>2</sub> without blending.<br><b>Reason (R):</b> Alleles segregate from each other during gamete formation so that each gamete receives only one allele.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. The reappearance of the recessive trait unchanged in F2 (A) is because alleles don't blend — they segregate cleanly during meiosis, with each gamete receiving only one allele (R). Segregation ensures alleles are transmitted intact, explaining lack of blending." },

  // ───── TOPIC: INCOMPLETE DOMINANCE ─────
  { id: 89, topic: "Incomplete Dominance", q: "In snapdragon (<i>Antirrhinum</i>), a cross between true-breeding red-flowered (RR) and white-flowered (rr) plants produces F<sub>1</sub> with:", options: ["All red flowers", "All white flowers", "All pink flowers", "Red and white flowers in 3:1 ratio"], correct: 2, explanation: "NCERT states: 'In a cross between true-breeding red-flowered (RR) and true-breeding white-flowered plants (rr), the F1 (Rr) was Pink.' This is because R is not completely dominant over r — this is incomplete dominance." },

  { id: 90, topic: "Incomplete Dominance", q: "The F<sub>2</sub> phenotypic ratio in a cross showing incomplete dominance is:", options: ["3:1", "1:2:1", "9:3:3:1", "1:1:1:1"], correct: 1, explanation: "In incomplete dominance, the F2 ratio is 1 Red (RR) : 2 Pink (Rr) : 1 White (rr) = 1:2:1. Unlike complete dominance where phenotypic ratio is 3:1, here the phenotypic ratio equals the genotypic ratio (1:2:1) because heterozygotes are distinguishable." },

  { id: 91, topic: "Incomplete Dominance", q: "In incomplete dominance, the F<sub>2</sub> <b>genotypic</b> ratio is:", options: ["3:1", "1:1", "1:2:1", "9:3:3:1"], correct: 2, explanation: "NCERT states: 'the genotype ratios were exactly as we would expect in any Mendelian monohybrid cross' — i.e., 1:2:1 (1 RR : 2 Rr : 1 rr). The key point is that the genotypic ratio remains 1:2:1 regardless of complete or incomplete dominance." },

  { id: 92, topic: "Incomplete Dominance", q: "Which of the following is a unique feature of incomplete dominance compared to complete dominance?", options: ["Genotypic ratio in F2 changes from 1:2:1 to 3:1", "Phenotypic ratio in F2 becomes same as genotypic ratio (1:2:1)", "F1 shows parental phenotype", "F2 shows only two phenotypic classes"], correct: 1, explanation: "In incomplete dominance, since heterozygotes (Rr = Pink) are distinguishable from homozygous dominant (RR = Red), the phenotypic ratio becomes 1:2:1 — identical to the genotypic ratio. In complete dominance, phenotypic ratio is 3:1 while genotypic is 1:2:1." },

  { id: 93, topic: "Incomplete Dominance", q: "<b>Assertion (A):</b> In snapdragon, the F<sub>1</sub> hybrid (Rr) shows pink flower colour.<br><b>Reason (R):</b> The allele R is completely dominant over allele r.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 2, explanation: "Assertion is true — F1 Rr shows pink flowers. Reason is FALSE — NCERT states 'R was not completely dominant over r.' If R were completely dominant, Rr would appear red (like RR), not pink. This is an example of INCOMPLETE dominance." },

  { id: 94, topic: "Incomplete Dominance", q: "The inheritance of flower colour in snapdragon is a good example of incomplete dominance. Which of the following is correct about this cross?<br>(i) F<sub>1</sub> phenotype does not resemble either parent<br>(ii) F<sub>1</sub> phenotype is in between the two parents<br>(iii) F<sub>2</sub> shows 3:1 phenotypic ratio<br>(iv) F<sub>2</sub> genotypic ratio is 1:2:1", options: ["(i), (ii), (iii) and (iv)", "(i), (ii) and (iv) only", "(i) and (iii) only", "(ii) and (iii) only"], correct: 1, explanation: "Statement (iii) is INCORRECT — F2 phenotypic ratio is 1:2:1 (not 3:1) in incomplete dominance. Statements (i), (ii), and (iv) are correct. NCERT states F1 had a phenotype 'that did not resemble either of the two parents and was in between the two.'" },

  { id: 95, topic: "Incomplete Dominance", q: "Snapdragon is also known as:", options: ["Mirabilis jalapa", "Antirrhinum sp.", "Pisum sativum", "Lathyrus odoratus"], correct: 1, explanation: "NCERT refers to snapdragon as 'dog flower (snapdragon or Antirrhinum sp.).' Mirabilis jalapa is four o'clock plant, Pisum sativum is garden pea, and Lathyrus odoratus is sweet pea." },

  { id: 96, topic: "Incomplete Dominance", q: "If two pink-flowered snapdragon plants (Rr) are crossed, the expected offspring ratio will be:", options: ["All pink", "1 Red : 2 Pink : 1 White", "3 Red : 1 White", "1 Red : 1 Pink"], correct: 1, explanation: "Rr × Rr → ¼ RR (Red) : ½ Rr (Pink) : ¼ rr (White) = 1:2:1. Since this shows incomplete dominance, heterozygotes are pink and distinguishable from both homozygous types." },

  { id: 97, topic: "Incomplete Dominance", q: "Which of the following correctly differentiates complete dominance from incomplete dominance?", options: ["In complete dominance genotypic ratio is 3:1; in incomplete dominance it is 1:2:1", "In complete dominance F2 phenotypic ratio is 3:1; in incomplete dominance it is 1:2:1", "In complete dominance F1 is intermediate; in incomplete dominance F1 resembles one parent", "In both, phenotypic ratio in F2 is 3:1"], correct: 1, explanation: "In complete dominance, F2 phenotypic ratio is 3:1 (heterozygote indistinguishable from homozygous dominant). In incomplete dominance, F2 phenotypic ratio is 1:2:1 (heterozygote distinguishable as intermediate). The genotypic ratio is 1:2:1 in BOTH cases. Option A is wrong because genotypic ratio is 1:2:1 in both." },

  // ───── TOPIC: CONCEPT OF DOMINANCE ─────
  { id: 98, topic: "Concept of Dominance", q: "According to the NCERT explanation of dominance, a modified allele could be responsible for production of:<br>(i) Normal/less efficient enzyme<br>(ii) A non-functional enzyme<br>(iii) No enzyme at all<br>Select the correct option:", options: ["(i) and (ii) only", "(ii) and (iii) only", "(i), (ii) and (iii)", "(i) only"], correct: 2, explanation: "NCERT lists all three possibilities for a modified allele: (i) normal/less efficient enzyme, (ii) non-functional enzyme, or (iii) no enzyme at all. All three are theoretically possible outcomes of allele modification." },

  { id: 99, topic: "Concept of Dominance", q: "When a modified allele produces a <b>normal or less efficient enzyme</b>, it is:", options: ["Dominant over the unmodified allele", "Lethal to the organism", "Equivalent to the unmodified allele", "Always recessive"], correct: 2, explanation: "NCERT states: 'the modified allele is equivalent to the unmodified allele, i.e., it will produce the same phenotype/trait.' Such equivalent allele pairs are described as 'very common.' It is neither dominant over nor recessive to the original." },

  { id: 100, topic: "Concept of Dominance", q: "The recessive trait is expressed when the modified allele produces:", options: ["A normal enzyme", "A more efficient enzyme", "A non-functional enzyme or no enzyme at all", "A regulatory protein that enhances gene expression"], correct: 2, explanation: "NCERT states: 'the recessive trait is seen due to non-functional enzyme or because no enzyme is produced.' When the modified allele produces no functional product, only the unmodified allele determines phenotype — making it dominant." },

  { id: 101, topic: "Concept of Dominance", q: "<b>Assertion (A):</b> The unmodified (functioning) allele which represents the original phenotype is the dominant allele.<br><b>Reason (R):</b> Equivalent allele pairs where both produce functional enzyme are very common in nature.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 1, explanation: "Both A and R are true statements from NCERT. However, R does not explain A. A talks about dominance (when one allele is non-functional), while R talks about equivalent allele pairs (when both produce functional enzyme — no dominance/recessiveness distinction). These are different scenarios." },

  { id: 102, topic: "Concept of Dominance", q: "Select the <b>incorrect</b> statement about the molecular basis of dominance:", options: ["Every gene contains information to express a particular trait", "In a diploid organism, there are two copies of each gene", "Two alleles in a heterozygote are always identical", "Dominance is related to the functional nature of the enzyme produced by an allele"], correct: 2, explanation: "NCERT states: 'these two alleles need not always be identical, as in a heterozygote.' In fact, a heterozygote BY DEFINITION has two different (non-identical) alleles. Statement C is incorrect." },

  { id: 103, topic: "Concept of Dominance", q: "Equivalent allele pairs are those where:", options: ["One allele produces a non-functional enzyme", "Neither allele produces any enzyme", "The modified allele produces a normal or less efficient but functional enzyme", "Both alleles undergo deletion"], correct: 2, explanation: "NCERT states: 'the modified allele is equivalent to the unmodified allele, i.e., it will produce the same phenotype/trait, i.e., result in the transformation of substrate S. Such equivalent allele pairs are very common.' This occurs when the modified allele still produces a functional (normal/less efficient) enzyme." },

  { id: 104, topic: "Concept of Dominance", q: "In a diploid organism, the phenotype of a heterozygote depends on the functioning of the unmodified allele when the modified allele produces:", options: ["A normal enzyme", "A less efficient but functional enzyme", "Both (A) and (B)", "A non-functional enzyme or no enzyme"], correct: 3, explanation: "When the modified allele produces a non-functional enzyme or no enzyme at all, the phenotype becomes dependent entirely on the unmodified (functioning) allele. When modified allele produces normal/less efficient enzyme (options A, B), phenotype is same regardless — these are equivalent alleles." },

  { id: 105, topic: "Concept of Dominance", q: "A gene contains information for producing an enzyme. If both alleles in a heterozygote produce functional enzyme, the most likely outcome is:", options: ["The organism will show the recessive phenotype", "The organism will die due to overproduction of enzyme", "Both alleles are equivalent and the same phenotype is produced", "Incomplete dominance will be observed"], correct: 2, explanation: "NCERT states: when the modified allele produces normal/less efficient (but functional) enzyme, 'the modified allele is equivalent to the unmodified allele, i.e., it will produce the same phenotype/trait.' Such equivalent allele pairs are very common. No dominance/recessiveness distinction exists in this case." },

  // ───── TOPIC: CODOMINANCE ─────
  { id: 106, topic: "Codominance", q: "In codominance, the F<sub>1</sub> generation:", options: ["Resembles one of the two parents", "Shows an intermediate phenotype between both parents", "Resembles both parents simultaneously", "Does not express any parental trait"], correct: 2, explanation: "NCERT states: 'in the case of co-dominance the F1 generation resembles both parents.' This is different from dominance (resembles one parent) and incomplete dominance (intermediate between both). Both alleles are expressed fully and simultaneously." },

  { id: 107, topic: "Codominance", q: "ABO blood groups in humans are controlled by the gene <b>I</b> which has:", options: ["Two alleles", "Three alleles", "Four alleles", "Six alleles"], correct: 1, explanation: "NCERT states: 'The gene I has three alleles IA, IB and i.' Though the gene has 3 alleles in the population, each individual (being diploid) possesses only any two of the three. Students sometimes confuse 6 genotypes with 6 alleles." },

  { id: 108, topic: "Codominance", q: "The sugar polymers on the surface of red blood cells are controlled by:", options: ["Genes on the Y chromosome", "Mitochondrial DNA", "The gene I on autosomes", "Environmental factors"], correct: 2, explanation: "NCERT states: 'The plasma membrane of the red blood cells has sugar polymers that protrude from its surface and the kind of sugar is controlled by the gene.' The gene I controls ABO blood groups through sugar polymer expression on RBCs." },

  { id: 109, topic: "Codominance", q: "Which of the following statements about allele <b>i</b> of the ABO blood group system is correct?", options: ["It produces a slightly different form of sugar", "It produces the same sugar as IA", "It does not produce any sugar", "It produces both A and B type sugars"], correct: 2, explanation: "NCERT clearly states: 'allele i does not produce any sugar.' Alleles IA and IB produce slightly different forms of sugar, while allele i is non-functional in sugar production. This is why i is recessive to both IA and IB." },

  { id: 110, topic: "Codominance", q: "The relationship between alleles I<sup>A</sup> and I<sup>B</sup> with respect to allele <b>i</b> is:", options: ["Codominance", "Incomplete dominance", "Complete dominance", "Epistasis"], correct: 2, explanation: "NCERT states: 'IA and IB are completely dominant over i.' When IA and i are present, only IA expresses; when IB and i are present, only IB expresses. The codominance relationship exists between IA and IB (with each other), NOT between IA/IB and i." },

  { id: 111, topic: "Codominance", q: "When alleles I<sup>A</sup> and I<sup>B</sup> are present together in an individual, the result is:", options: ["Only IA is expressed", "Only IB is expressed", "An intermediate phenotype is expressed", "Both IA and IB express their own types of sugars"], correct: 3, explanation: "NCERT states: 'when IA and IB are present together they both express their own types of sugars: this is because of co-dominance. Hence red blood cells have both A and B types of sugars.' Neither allele masks the other." },

  { id: 112, topic: "Codominance", q: "The total number of possible <b>genotypes</b> for ABO blood grouping in humans is:", options: ["3", "4", "6", "8"], correct: 2, explanation: "NCERT states: 'Since there are three different alleles, there are six different combinations of these three alleles that are possible, and therefore, a total of six different genotypes.' These are: IAIA, IAi, IBIB, IBi, IAIB, ii." },

  { id: 113, topic: "Codominance", q: "The total number of <b>phenotypes</b> for ABO blood grouping in humans is:", options: ["3", "4", "6", "2"], correct: 1, explanation: "There are 4 phenotypes: Blood group A (IAIA or IAi), Blood group B (IBIB or IBi), Blood group AB (IAIB), and Blood group O (ii). Though there are 6 genotypes, the phenotypes are only 4 because IA is completely dominant over i, and IB is completely dominant over i." },

  { id: 114, topic: "Codominance", q: "<b>Assertion (A):</b> Blood group AB is an example of codominance.<br><b>Reason (R):</b> In individuals with genotype I<sup>A</sup>I<sup>B</sup>, both alleles express their own type of sugar on RBC surface.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both A and R are true. Blood group AB (IAIB) is codominant because both IA and IB express their respective sugars simultaneously on RBC surface. R provides the molecular mechanism explaining why AB shows codominance (A)." },

  { id: 115, topic: "Codominance", q: "Which of the following genotypes will result in blood group <b>O</b>?", options: ["IAIA", "IAi", "IAIB", "ii"], correct: 3, explanation: "Blood group O results from genotype ii only. Since allele i does not produce any sugar, an individual homozygous for i (ii) has no A or B sugars on RBC surface. This is the only genotype for blood group O — there is no heterozygous form for O." },

  { id: 116, topic: "Codominance", q: "Consider the following genotype-phenotype pairs:<br>(i) I<sup>A</sup>I<sup>A</sup> — Blood group A<br>(ii) I<sup>A</sup>i — Blood group A<br>(iii) I<sup>B</sup>I<sup>B</sup> — Blood group AB<br>(iv) I<sup>A</sup>I<sup>B</sup> — Blood group AB<br>Which are correctly matched?", options: ["(i), (ii) and (iv) only", "(i), (ii), (iii) and (iv)", "(iii) and (iv) only", "(i) and (iv) only"], correct: 0, explanation: "Statement (iii) is INCORRECT — IBIB gives Blood group B (not AB). Blood group AB is produced ONLY by genotype IAIB (codominance). IAIA and IAi both give blood group A (because IA is completely dominant over i). A very common student trap." },

  { id: 117, topic: "Codominance", q: "Multiple alleles can be found only when:", options: ["A single individual is studied", "Two homozygous parents are crossed", "Population studies are made", "Inbreeding is carried out for several generations"], correct: 2, explanation: "NCERT states: 'Since in an individual only two alleles can be present, multiple alleles can be found only when population studies are made.' A diploid individual can carry at most 2 of the 3 alleles. The third allele is identified only by studying other individuals in the population." },

  { id: 118, topic: "Codominance", q: "<b>Assertion (A):</b> The ABO blood grouping system provides a good example of multiple alleles.<br><b>Reason (R):</b> There are more than two alleles governing the same character, though an individual possesses only two.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. ABO has 3 alleles (IA, IB, i) governing blood group — more than 2, hence multiple alleles (A). Each individual, being diploid, carries only any two (R). R correctly explains what makes ABO a multiple allele system." },

  { id: 119, topic: "Codominance", q: "Select the <b>incorrect</b> statement about codominance:", options: ["F1 resembles both parents", "Both alleles express simultaneously in heterozygote", "F1 shows an intermediate phenotype between parents", "ABO blood group AB is an example"], correct: 2, explanation: "An intermediate phenotype is characteristic of INCOMPLETE dominance (e.g., pink in snapdragon), NOT codominance. In codominance, BOTH parental traits are expressed simultaneously and fully (e.g., both A and B sugars in AB blood group). This is the most common NEET confusion." },

  { id: 120, topic: "Codominance", q: "Which of the following correctly differentiates <b>codominance</b> from <b>incomplete dominance</b>?", options: ["In codominance F1 is intermediate; in incomplete dominance F1 resembles both parents", "In codominance both alleles express fully; in incomplete dominance F1 shows a blended/intermediate phenotype", "Both show the same F1 phenotype", "Codominance shows 3:1 ratio in F2; incomplete dominance shows 1:2:1"], correct: 1, explanation: "In codominance, both alleles express their products fully and simultaneously (e.g., both A and B sugars). In incomplete dominance, the F1 is intermediate between both parents (e.g., pink from red × white). Option A reverses the two. Option D is wrong — both show 1:2:1 phenotypic ratio in F2." },

  { id: 121, topic: "Codominance", q: "A person with blood group A can have which of the following genotypes?", options: ["I<sup>A</sup>I<sup>A</sup> only", "I<sup>A</sup>i only", "I<sup>A</sup>I<sup>A</sup> or I<sup>A</sup>i", "I<sup>A</sup>I<sup>B</sup>"], correct: 2, explanation: "Blood group A can result from IAIA (homozygous) or IAi (heterozygous). In both cases, IA is expressed (i does not produce any sugar, so IA dominates). IAIB gives blood group AB, not A." },

  { id: 122, topic: "Codominance", q: "The alleles I<sup>A</sup> and I<sup>B</sup> produce:", options: ["Identical forms of sugar", "Slightly different forms of sugar", "No sugar at all", "Proteins instead of sugars"], correct: 1, explanation: "NCERT states: 'The alleles IA and IB produce a slightly different form of the sugar.' These slightly different sugars (type A and type B) on RBC surface determine the blood group. Allele i produces NO sugar." },

  { id: 123, topic: "Codominance", q: "How many genotypes of ABO blood groups produce the <b>same</b> phenotype?<br>(i) I<sup>A</sup>I<sup>A</sup> and I<sup>A</sup>i → Blood group A<br>(ii) I<sup>B</sup>I<sup>B</sup> and I<sup>B</sup>i → Blood group B<br>(iii) I<sup>A</sup>I<sup>B</sup> → Blood group AB<br>(iv) ii → Blood group O", options: ["Only pair (i) shows two genotypes for same phenotype", "Both pairs (i) and (ii) show two genotypes for same phenotype", "All four pairs show two genotypes for same phenotype", "None show two genotypes for same phenotype"], correct: 1, explanation: "Blood group A has 2 genotypes (IAIA and IAi) and Blood group B has 2 genotypes (IBIB and IBi). Blood group AB has only 1 genotype (IAIB) and Blood group O has only 1 genotype (ii). So pairs (i) and (ii) both show 2 genotypes producing the same phenotype." },

  { id: 124, topic: "Codominance", q: "Starch synthesis in pea seeds is controlled by one gene with alleles B and b. In Bb heterozygotes:", options: ["Seeds are wrinkled and starch grains are large", "Seeds are round and starch grains are large", "Seeds are round and starch grains are intermediate in size", "Seeds are wrinkled and starch grains are intermediate in size"], correct: 2, explanation: "NCERT states: 'Heterozygotes produce round seeds, and so B seems to be the dominant allele. But, the starch grains produced are of intermediate size in Bb seeds.' So Bb = Round seeds (dominance) + Intermediate starch grains (incomplete dominance)." },

  { id: 125, topic: "Codominance", q: "<b>Assertion (A):</b> In pea, the allele B shows dominance for seed shape but incomplete dominance for starch grain size.<br><b>Reason (R):</b> Dominance is not an autonomous feature of a gene and depends on the phenotype chosen to examine.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. Bb seeds are round (B dominant for shape) but have intermediate starch grains (incomplete dominance for starch grain size). NCERT states: 'dominance is not an autonomous feature of a gene... It depends... on the particular phenotype that we choose to examine.' R perfectly explains why the same gene shows different dominance patterns." },

  { id: 126, topic: "Codominance", q: "A single gene product producing more than one effect is called:", options: ["Multiple allelism", "Codominance", "Pleiotropy", "Epistasis"], correct: 2, explanation: "NCERT states: 'Occasionally, a single gene product may produce more than one effect.' This phenomenon is called pleiotropy. The starch synthesis gene in pea affects both seed shape AND starch grain size — a pleiotropic effect. Multiple allelism is about many alleles of one gene." },

  { id: 127, topic: "Codominance", q: "In pea, BB homozygotes produce:", options: ["Small starch grains and wrinkled seeds", "Large starch grains and round seeds", "Intermediate starch grains and round seeds", "No starch grains and wrinkled seeds"], correct: 1, explanation: "NCERT states: 'Starch is synthesised effectively by BB homozygotes and therefore, large starch grains are produced.' And 'After maturation of the seeds, BB seeds are round.' So BB = large starch grains + round seeds." },

  { id: 128, topic: "Codominance", q: "In pea, bb homozygotes produce wrinkled seeds because:", options: ["They produce large starch grains that distort the seed coat", "They have lesser efficiency in starch synthesis producing smaller starch grains", "They produce no starch at all", "The b allele codes for a wrinkle-promoting protein"], correct: 1, explanation: "NCERT states: 'bb homozygotes have lesser efficiency in starch synthesis and produce smaller starch grains. After maturation of the seeds... bb seeds are wrinkled.' The smaller starch grains lead to loss of water and wrinkling upon seed maturation." },

  { id: 129, topic: "Codominance", q: "Consider the following:<br>(A) Codominance — F<sub>1</sub> resembles both parents<br>(B) Dominance — F<sub>1</sub> resembles one parent<br>(C) Incomplete dominance — F<sub>1</sub> is intermediate<br>(D) Codominance — F<sub>1</sub> is intermediate<br>Select the correct statements:", options: ["(A), (B), (C) and (D)", "(A), (B) and (C) only", "(B) and (D) only", "(A) and (D) only"], correct: 1, explanation: "Statement (D) is INCORRECT — in codominance, F1 resembles BOTH parents (not intermediate). Intermediate phenotype is seen in incomplete dominance, not codominance. Statements A, B, and C correctly describe codominance, dominance, and incomplete dominance respectively." },

  { id: 130, topic: "Codominance", q: "A couple has blood groups A (genotype I<sup>A</sup>i) and B (genotype I<sup>B</sup>i). What blood groups are possible in their offspring?", options: ["A and B only", "A, B and AB only", "A, B, AB and O", "AB only"], correct: 2, explanation: "IAi × IBi → IAIB (AB), IAi (A), IBi (B), ii (O). All four blood groups are possible in 1:1:1:1 ratio. This is a classic NEET application question. Students often forget that both parents carry the i allele, making blood group O possible." },

  { id: 131, topic: "Codominance", q: "Which of the following is <b>incorrect</b> about multiple alleles?", options: ["More than two alleles govern the same character", "An individual can possess all three alleles simultaneously", "Multiple alleles can be detected through population studies", "ABO blood group system is an example"], correct: 1, explanation: "NCERT clearly states: 'Since in an individual only two alleles can be present, multiple alleles can be found only when population studies are made.' A diploid individual can carry only 2 of the 3 alleles at a time. Option B is incorrect — an individual CANNOT possess all three alleles." },

  { id: 132, topic: "Codominance", q: "<b>Assertion (A):</b> Dominance is not an autonomous feature of a gene.<br><b>Reason (R):</b> The same allele B in pea shows dominance for seed shape but incomplete dominance for starch grain size.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states: 'dominance is not an autonomous feature of a gene.' The example of allele B showing dominance for one phenotype (seed shape) and incomplete dominance for another (starch grain size) perfectly demonstrates and explains why dominance is not absolute." },

  { id: 133, topic: "Codominance", q: "The sugar polymers determining ABO blood groups protrude from the surface of:", options: ["White blood cells", "Platelets", "Plasma membrane of red blood cells", "Nuclear membrane of blood cells"], correct: 2, explanation: "NCERT states: 'The plasma membrane of the red blood cells has sugar polymers that protrude from its surface.' These sugar polymers (antigens) on RBC surface determine the ABO blood group. Note: RBCs are enucleated, so nuclear membrane is irrelevant." },

  { id: 134, topic: "Codominance", q: "If the starch grain size in pea is considered as the phenotype, the alleles B and b show:", options: ["Complete dominance", "Codominance", "Incomplete dominance", "Epistasis"], correct: 2, explanation: "NCERT states: 'if starch grain size is considered as the phenotype, then from this angle, the alleles show incomplete dominance.' Bb produces intermediate-sized starch grains (neither large like BB nor small like bb). For seed shape, B shows complete dominance." },

  { id: 135, topic: "Codominance", q: "Consider the following statements:<br>(i) I<sup>A</sup> and I<sup>B</sup> are codominant with each other<br>(ii) I<sup>A</sup> and I<sup>B</sup> are both completely dominant over i<br>(iii) Allele i produces a different type of sugar<br>(iv) Blood group O results from genotype ii<br>Which of the above are correct?", options: ["(i), (ii) and (iv) only", "(i), (ii), (iii) and (iv)", "(i) and (ii) only", "(ii), (iii) and (iv) only"], correct: 0, explanation: "Statement (iii) is INCORRECT — allele i does NOT produce any sugar (not a different type). NCERT states: 'allele i does not produce any sugar.' Statements (i), (ii), and (iv) are all correct as per NCERT. This is a critical trap — students assume i produces a third type of sugar." },

  // ───── TOPIC: INHERITANCE OF TWO GENES ─────
  { id: 136, topic: "Inheritance of Two Genes", q: "In Mendel's dihybrid cross, the parental genotypes were:", options: ["RrYy × RrYy", "RRYY × rryy", "RRyy × rrYY", "Rryy × rrYy"], correct: 1, explanation: "NCERT states Mendel crossed a pea plant with yellow, round seeds (RRYY) with one having green, wrinkled seeds (rryy). Both parents are homozygous for both characters. The F1 hybrid resulting from this cross is RrYy." },

  { id: 137, topic: "Inheritance of Two Genes", q: "The F<sub>1</sub> hybrid from the cross RRYY × rryy has the genotype:", options: ["RRYY", "rryy", "RrYy", "RRYy"], correct: 2, explanation: "NCERT states: 'The gametes RY and ry unite on fertilisation to produce the F1 hybrid RrYy.' The F1 is heterozygous for both characters — round seed shape and yellow seed colour." },

  { id: 138, topic: "Inheritance of Two Genes", q: "In Mendel's dihybrid cross, which of the following is <b>dominant</b>?<br>(i) Yellow colour over green<br>(ii) Green colour over yellow<br>(iii) Round shape over wrinkled<br>(iv) Wrinkled shape over round", options: ["(i) and (iii) only", "(ii) and (iv) only", "(i) and (iv) only", "(ii) and (iii) only"], correct: 0, explanation: "NCERT states: 'yellow colour was dominant over green and round shape dominant over wrinkled.' So Yellow > Green and Round > Wrinkled. These results were identical to separate monohybrid crosses." },

  { id: 139, topic: "Inheritance of Two Genes", q: "When Mendel self-hybridised the F<sub>1</sub> dihybrid plants (RrYy), each character pair in F<sub>2</sub> segregated in the ratio:", options: ["1:1", "9:3:3:1", "1:2:1", "3:1"], correct: 3, explanation: "NCERT states: 'he found that ¾th of F2 plants had yellow seeds and ¼th had green. The yellow and green colour segregated in a 3:1 ratio. Round and wrinkled seed shape also segregated in a 3:1 ratio; just like in a monohybrid cross.' Each pair independently shows 3:1." },

  { id: 140, topic: "Inheritance of Two Genes", q: "The F<sub>1</sub> dihybrid RrYy produces how many types of gametes?", options: ["2 types", "4 types", "8 types", "16 types"], correct: 1, explanation: "NCERT states: 'Thus there are four genotypes of gametes (four types of pollen and four types of eggs). The four types are RY, Ry, rY and ry each with a frequency of 25 per cent or ¼ of the total gametes produced.' A dihybrid heterozygote produces 4 gamete types." },

  { id: 141, topic: "Inheritance of Two Genes", q: "Each type of gamete produced by the F<sub>1</sub> dihybrid (RrYy) has a frequency of:", options: ["50% or ½", "12.5% or ⅛", "25% or ¼", "33.3% or ⅓"], correct: 2, explanation: "NCERT states the four gamete types (RY, Ry, rY, ry) are each produced with 'a frequency of 25 per cent or ¼ of the total gametes produced.' This is because R/r segregation is independent of Y/y segregation." },

  { id: 142, topic: "Inheritance of Two Genes", q: "The Punnett square for a dihybrid cross (RrYy × RrYy) has:", options: ["4 squares", "8 squares", "16 squares", "32 squares"], correct: 2, explanation: "NCERT mentions: 'Although there are 16 squares...' Since each parent produces 4 types of gametes, the Punnett square is 4 × 4 = 16 boxes representing all possible zygote combinations." },

  { id: 143, topic: "Inheritance of Two Genes", q: "<b>Assertion (A):</b> The results of Mendel's dihybrid cross were consistent with his monohybrid cross results.<br><b>Reason (R):</b> Each character pair in the dihybrid cross segregated independently in a 3:1 ratio, just like in a monohybrid cross.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states the dihybrid results were 'identical to those that he got when he made separate monohybrid crosses.' This consistency exists because each character pair segregates independently in 3:1 (R), confirming the monohybrid pattern holds within dihybrid crosses (A)." },

  { id: 144, topic: "Inheritance of Two Genes", q: "In the F<sub>2</sub> of a dihybrid cross, the phenotype <b>wrinkled green</b> (rryy) appears in the proportion of:", options: ["9/16", "3/16", "1/16", "1/4"], correct: 2, explanation: "In the 9:3:3:1 ratio, wrinkled green (rryy) is the double recessive class appearing at 1/16 frequency. It represents the only genotype where both recessive alleles are homozygous. 9/16 is round yellow, 3/16 each for wrinkled yellow and round green." },

  { id: 145, topic: "Inheritance of Two Genes", q: "In the F<sub>2</sub> of a dihybrid cross (RrYy × RrYy), the number of distinct <b>phenotypes</b> is:", options: ["2", "4", "9", "16"], correct: 1, explanation: "There are 4 phenotypic classes: Round Yellow (9/16), Wrinkled Yellow (3/16), Round Green (3/16), and Wrinkled Green (1/16). Students often confuse 16 (total squares) or 9 (genotypes) with 4 (phenotypes)." },

  { id: 146, topic: "Inheritance of Two Genes", q: "In the F<sub>2</sub> of a dihybrid cross, the total number of distinct <b>genotypes</b> is:", options: ["4", "9", "16", "3"], correct: 1, explanation: "A dihybrid cross produces 9 distinct genotypes in F2: RRYY, RRYy, RRyy, RrYY, RrYy, Rryy, rrYY, rrYy, rryy. This is because each gene has 3 genotypes (e.g., RR, Rr, rr) and 3 × 3 = 9. NCERT itself asks the student to 'note them down' — implying more than 4." },

  { id: 147, topic: "Inheritance of Two Genes", q: "The dihybrid F<sub>2</sub> phenotypic ratio 9:3:3:1 can be derived as:", options: ["(3:1) + (3:1)", "(3:1) × (3:1)", "(1:2:1) × (3:1)", "(9:7) × (1:1)"], correct: 1, explanation: "NCERT states: 'The ratio of 9:3:3:1 can be derived as a combination series of 3 yellow : 1 green, with 3 round : 1 wrinkled.' The derivation is: (3 Round : 1 Wrinkled) × (3 Yellow : 1 Green) = 9:3:3:1. It is a product (×), not a sum (+)." },

  { id: 148, topic: "Inheritance of Two Genes", q: "In the F<sub>2</sub> of a dihybrid cross, the proportion of offspring showing <b>at least one dominant character</b> is:", options: ["9/16", "15/16", "3/16", "12/16"], correct: 1, explanation: "Offspring with at least one dominant character include: Round Yellow (9/16) + Wrinkled Yellow (3/16) + Round Green (3/16) = 15/16. Only wrinkled green (rryy) = 1/16 has NO dominant character. So 16/16 – 1/16 = 15/16." },

  { id: 149, topic: "Inheritance of Two Genes", q: "In the F<sub>2</sub> of a dihybrid cross, the proportion of offspring with <b>both recessive traits</b> is:", options: ["3/16", "1/16", "1/4", "9/16"], correct: 1, explanation: "The double recessive class (rryy — wrinkled green) appears at 1/16 frequency. This is the product of individual recessive frequencies: ¼ (rr) × ¼ (yy) = 1/16, demonstrating independent assortment." },

  { id: 150, topic: "Inheritance of Two Genes", q: "Which of the following gametes can <b>NOT</b> be produced by a plant with genotype RrYy?", options: ["RY", "Ry", "RR", "ry"], correct: 2, explanation: "A gamete contains only ONE allele from each gene pair (due to segregation). RR contains two alleles of the same gene, which is impossible in a gamete. The four gamete types from RrYy are RY, Ry, rY, and ry only." },

  { id: 151, topic: "Inheritance of Two Genes", q: "In a dihybrid cross, the <b>recombinant phenotypes</b> (new combinations not seen in parents) are:", options: ["Round Yellow and Wrinkled Green", "Wrinkled Yellow and Round Green", "Round Yellow and Round Green", "Wrinkled Yellow and Wrinkled Green"], correct: 1, explanation: "Parents were Round Yellow (RRYY) and Wrinkled Green (rryy). The new combinations (recombinants) are Wrinkled Yellow and Round Green — these represent combinations of traits not present in either parent. Round Yellow and Wrinkled Green are parental types." },

  { id: 152, topic: "Inheritance of Two Genes", q: "<b>Assertion (A):</b> The phenotypic ratio 9:3:3:1 in F<sub>2</sub> of a dihybrid cross is also the genotypic ratio.<br><b>Reason (R):</b> In a dihybrid cross, 16 different genotypic combinations are possible.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is false but R is true", "Both A and R are false"], correct: 2, explanation: "Assertion is FALSE — the phenotypic ratio is 9:3:3:1 but the genotypic ratio is NOT 9:3:3:1. There are 9 different genotypes in a dihybrid F2. Reason is TRUE — 16 combinations are possible in the Punnett square (4 × 4). NCERT asks 'Is the genotypic ratio also 9:3:3:1?' — implying it is not." },

  { id: 153, topic: "Inheritance of Two Genes", q: "In the F<sub>2</sub> of a dihybrid cross, the fraction of offspring that are <b>homozygous for both dominant traits</b> (RRYY) is:", options: ["9/16", "1/16", "3/16", "4/16"], correct: 1, explanation: "RRYY is just one of the 16 possible zygotic combinations. The probability of RR = ¼ and YY = ¼; so RRYY = ¼ × ¼ = 1/16. Students often confuse 9/16 (all round yellow phenotypes) with 1/16 (only RRYY genotype)." },

  { id: 154, topic: "Inheritance of Two Genes", q: "In the F<sub>2</sub> of a dihybrid cross, the most frequent genotype is:", options: ["RRYY", "RrYy", "rryy", "RRyy"], correct: 1, explanation: "RrYy (double heterozygote) appears 4 times out of 16 in the Punnett square (4/16 = ¼). This is the most frequent single genotype. RRYY, rryy, RRyy, rrYY each appear only 1/16 of the time." },

  { id: 155, topic: "Inheritance of Two Genes", q: "Consider the F<sub>2</sub> offspring of a dihybrid cross. The ratio of <b>round seeds</b> to <b>wrinkled seeds</b> (irrespective of colour) is:", options: ["9:7", "1:1", "3:1", "9:3"], correct: 2, explanation: "NCERT states: 'Round and wrinkled seed shape also segregated in a 3:1 ratio.' In F2: Round seeds = 9 (Round Yellow) + 3 (Round Green) = 12/16 = ¾. Wrinkled seeds = 3 (Wrinkled Yellow) + 1 (Wrinkled Green) = 4/16 = ¼. Ratio = 3:1." },

  { id: 156, topic: "Inheritance of Two Genes", q: "Consider the following:<br>(i) Law of Segregation is derived from monohybrid crosses<br>(ii) Law of Independent Assortment is derived from dihybrid crosses<br>(iii) Law of Dominance explains 9:3:3:1 ratio<br>(iv) Law of Independent Assortment explains 3:1 ratio<br>Which statements are correct?", options: ["(i) and (ii) only", "(i), (ii) and (iii)", "(i), (ii), (iii) and (iv)", "(iii) and (iv) only"], correct: 0, explanation: "Statements (i) and (ii) are correct per NCERT. Statement (iii) is incorrect — Law of Dominance explains the 3:1 ratio (monohybrid), not 9:3:3:1. Statement (iv) is incorrect — Law of Independent Assortment explains the 9:3:3:1 ratio (dihybrid), not 3:1." },

  // ───── TOPIC: LAW OF INDEPENDENT ASSORTMENT ─────
  { id: 157, topic: "Law of Independent Assortment", q: "Mendel's Law of Independent Assortment states that:", options: ["Alleles of the same gene segregate from each other during gamete formation", "When two pairs of traits are combined in a hybrid, segregation of one pair is independent of the other pair", "In a dissimilar pair of factors, one member dominates the other", "Factors are discrete units that occur in pairs"], correct: 1, explanation: "NCERT states: 'The law states that when two pairs of traits are combined in a hybrid, segregation of one pair of characters is independent of the other pair of characters.' Option A describes Law of Segregation, Options C and D describe Law of Dominance." },

  { id: 158, topic: "Law of Independent Assortment", q: "The Law of Independent Assortment is based on observations from:", options: ["Monohybrid crosses only", "Dihybrid crosses", "Test crosses only", "Back crosses only"], correct: 1, explanation: "NCERT states: 'Based upon such observations on dihybrid crosses (crosses between plants differing in two traits) Mendel proposed... Mendel's Law of Independent Assortment.' The law requires studying at least two different character pairs simultaneously." },

  { id: 159, topic: "Law of Independent Assortment", q: "<b>Assertion (A):</b> In the F<sub>1</sub> dihybrid RrYy, segregation of R and r alleles is independent of segregation of Y and y alleles.<br><b>Reason (R):</b> This independent segregation produces four types of gametes in equal proportion.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states: '50 per cent R and 50 per cent r is independent from the segregation of 50 per cent Y and 50 per cent y.' This independence (A) results in four gamete types RY, Ry, rY, ry each at ¼ frequency (R). R is a direct consequence of A." },

  { id: 160, topic: "Law of Independent Assortment", q: "In the F<sub>1</sub> plant RrYy, what percentage of gametes bearing allele <b>r</b> will also have allele <b>Y</b>?", options: ["100%", "50%", "25%", "75%"], correct: 1, explanation: "NCERT states: '50 per cent of the r bearing gametes has Y and the other 50 per cent has y.' Since segregation of R/r is independent of Y/y, among the r-bearing gametes, Y and y are equally distributed (50% each)." },

  { id: 161, topic: "Law of Independent Assortment", q: "In the F<sub>1</sub> dihybrid RrYy, the gamete type <b>rY</b> is produced at what frequency?", options: ["½", "⅛", "¼", "1/16"], correct: 2, explanation: "NCERT states all four gamete types (RY, Ry, rY, ry) are produced 'each with a frequency of 25 per cent or ¼ of the total gametes produced.' This equal frequency is a direct consequence of independent assortment." },

  { id: 162, topic: "Law of Independent Assortment", q: "Select the <b>incorrect</b> statement about the Law of Independent Assortment:", options: ["It applies to dihybrid and polyhybrid crosses", "Segregation of one pair of alleles is independent of the other pair", "It was proposed based on monohybrid cross observations", "It results in the formation of new combinations in offspring"], correct: 2, explanation: "NCERT explicitly states the law was proposed 'Based upon such observations on dihybrid crosses.' It was NOT based on monohybrid crosses. The Law of Segregation comes from monohybrid crosses." },

  { id: 163, topic: "Law of Independent Assortment", q: "The independent segregation of two gene pairs during meiosis occurs in which generation?", options: ["Parental generation", "F1 generation", "F2 generation", "F3 generation"], correct: 1, explanation: "NCERT states: 'The Punnett square can be effectively used to understand the independent segregation of the two pairs of genes during meiosis and the production of eggs and pollen in the F1 RrYy plant.' The independent assortment occurs during gamete formation by the F1 dihybrid." },

  { id: 164, topic: "Law of Independent Assortment", q: "The gamete types produced by F<sub>1</sub> dihybrid RrYy are:", options: ["Rr, Yy", "RY, ry", "RY, Ry, rY, ry", "RR, Yy, rr, YY"], correct: 2, explanation: "NCERT states: 'The four types are RY, Ry, rY and ry each with a frequency of 25 per cent or ¼ of the total gametes produced.' Each gamete carries one allele from each gene pair. Options A and D show incorrect gamete compositions with both alleles of a gene." },

  { id: 165, topic: "Law of Independent Assortment", q: "<b>Assertion (A):</b> The 9:3:3:1 ratio in a dihybrid F<sub>2</sub> confirms that the two gene pairs assort independently.<br><b>Reason (R):</b> If the two gene pairs were not independent, the F<sub>2</sub> ratio would deviate from 9:3:3:1.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. The 9:3:3:1 ratio is a mathematical consequence of independent assortment — (3:1) × (3:1). If genes were linked or not independent, the ratio would deviate (e.g., more parental types, fewer recombinants). R explains why 9:3:3:1 specifically confirms independence." },

  // ───── TOPIC: CHROMOSOMAL THEORY OF INHERITANCE ─────
  { id: 166, topic: "Chromosomal Theory of Inheritance", q: "Mendel published his work on inheritance of characters in the year:", options: ["1856", "1863", "1865", "1900"], correct: 2, explanation: "NCERT states: 'Mendel published his work on inheritance of characters in 1865 but for several reasons, it remained unrecognised till 1900.' Students often confuse 1865 (publication) with 1856–1863 (experimental period) or 1900 (rediscovery)." },

  { id: 167, topic: "Chromosomal Theory of Inheritance", q: "Which of the following was <b>NOT</b> a reason for Mendel's work remaining unrecognised?", options: ["Poor communication in those days", "Concept of discrete non-blending factors was not accepted", "Use of mathematics in biology was unacceptable", "Mendel used a very small sample size in his experiments"], correct: 3, explanation: "NCERT mentions four reasons: poor communication, discrete/non-blending factors rejected, mathematical approach unacceptable, and no physical proof of factors. Mendel actually used a LARGE sampling size — not a reason for rejection." },

  { id: 168, topic: "Chromosomal Theory of Inheritance", q: "Consider the following reasons for non-recognition of Mendel's work:<br>(i) Communication was not easy<br>(ii) Concept of stable, discrete non-blending factors was not accepted<br>(iii) Mathematical approach was unacceptable to biologists<br>(iv) No physical proof for the existence of factors<br>How many of the above are mentioned in NCERT?", options: ["Two", "Three", "Four", "One"], correct: 2, explanation: "All four reasons are explicitly mentioned in NCERT: (i) poor communication, (ii) discrete non-blending factors not accepted due to continuous variation in nature, (iii) mathematics in biology was new and unacceptable, (iv) no physical proof of what factors were made of." },

  { id: 169, topic: "Chromosomal Theory of Inheritance", q: "Mendel's results were independently rediscovered in 1900 by:", options: ["Sutton, Boveri and Morgan", "Watson, Crick and Wilkins", "de Vries, Correns and von Tschermak", "Bateson, Punnett and Morgan"], correct: 2, explanation: "NCERT states: 'In 1900, three Scientists (de Vries, Correns and von Tschermak) independently rediscovered Mendel's results on the inheritance of characters.' Sutton and Boveri proposed chromosomal theory, and Morgan verified it — they did not rediscover Mendel's results." },

  { id: 170, topic: "Chromosomal Theory of Inheritance", q: "Chromosomes were named 'coloured bodies' because:", options: ["They are naturally coloured structures", "They were visualised by staining", "They contain coloured pigments", "They fluoresce under UV light"], correct: 1, explanation: "NCERT states: 'These were called chromosomes (colored bodies, as they were visualised by staining).' Chromosomes are not naturally coloured — they become visible when stained with dyes, hence the name 'coloured bodies.'" },

  { id: 171, topic: "Chromosomal Theory of Inheritance", q: "The chromosomal theory of inheritance was proposed by:", options: ["Thomas Hunt Morgan", "Gregor Mendel", "Walter Sutton and Theodore Boveri", "de Vries, Correns and von Tschermak"], correct: 2, explanation: "NCERT states: 'Sutton united the knowledge of chromosomal segregation with Mendelian principles and called it the chromosomal theory of inheritance.' Sutton and Boveri PROPOSED it; Morgan later EXPERIMENTALLY VERIFIED it. A very common NEET trap." },

  { id: 172, topic: "Chromosomal Theory of Inheritance", q: "<b>Assertion (A):</b> Sutton and Boveri argued that the behaviour of chromosomes was parallel to the behaviour of genes.<br><b>Reason (R):</b> Both chromosomes and genes occur in pairs, and homologous chromosomes separate during meiosis like alleles.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. Sutton and Boveri noted the parallelism between chromosomes and genes (A). This parallelism exists because both occur in pairs, alleles are located on homologous chromosomes, and they segregate during meiosis (R). R provides the evidence supporting A." },

  { id: 173, topic: "Chromosomal Theory of Inheritance", q: "By which year had the chromosome movement during meiosis been worked out?", options: ["1865", "1900", "1902", "1910"], correct: 2, explanation: "NCERT states: 'By 1902, the chromosome movement during meiosis had been worked out.' This enabled Sutton and Boveri to draw parallels between chromosome behaviour and Mendel's laws." },

  { id: 174, topic: "Chromosomal Theory of Inheritance", q: "The two alleles of a gene pair are located on:", options: ["The same chromosome at different loci", "Homologous sites on homologous chromosomes", "Non-homologous chromosomes", "The same chromatid"], correct: 1, explanation: "NCERT states: 'The two alleles of a gene pair are located on homologous sites on homologous chromosomes.' This is a key concept in the chromosomal theory — alleles occupy corresponding positions on homologous chromosomes." },

  { id: 175, topic: "Chromosomal Theory of Inheritance", q: "The experimental verification of the chromosomal theory of inheritance was carried out by:", options: ["Walter Sutton", "Theodore Boveri", "Thomas Hunt Morgan", "Alfred Sturtevant"], correct: 2, explanation: "NCERT states: 'experimental verification of the chromosomal theory of inheritance by Thomas Hunt Morgan and his colleagues.' Sutton and Boveri PROPOSED the theory; Morgan EXPERIMENTALLY VERIFIED it. This distinction is very frequently tested in NEET." },

  { id: 176, topic: "Chromosomal Theory of Inheritance", q: "Which of the following is <b>NOT</b> a reason why <i>Drosophila melanogaster</i> was suitable for Morgan's genetic studies?", options: ["It could be grown on simple synthetic medium", "It has a life cycle of about two weeks", "A single mating produces a large number of progeny", "It has a very large number of chromosomes"], correct: 3, explanation: "Drosophila has only 4 pairs of chromosomes (8 total) — a relatively small number. NCERT mentions the advantages as: simple synthetic medium, 2-week life cycle, large progeny, clear sex differentiation, and many hereditary variations visible with low power microscopes. Large chromosome number is NOT an advantage." },

  { id: 177, topic: "Chromosomal Theory of Inheritance", q: "Consider the following advantages of <i>Drosophila</i> for genetic studies:<br>(i) Grown on simple synthetic medium<br>(ii) Life cycle of about two weeks<br>(iii) Large number of progeny from single mating<br>(iv) Clear differentiation of sexes<br>(v) Many hereditary variations visible with low power microscopes<br>How many of these are mentioned in NCERT?", options: ["Three", "Four", "Five", "Two"], correct: 2, explanation: "All five advantages are explicitly mentioned in NCERT: simple synthetic medium, ~2-week life cycle, large progeny, easy sex differentiation, and many hereditary variations visible under low power microscopes." },

  { id: 178, topic: "Chromosomal Theory of Inheritance", q: "During Anaphase of meiosis I, the independent alignment of chromosome pairs at the metaphase plate explains:", options: ["Law of Dominance", "Law of Segregation only", "Law of Independent Assortment", "Linkage of genes"], correct: 2, explanation: "NCERT states that during Anaphase of meiosis I, 'the two chromosome pairs can align at the metaphase plate independently of each other.' This independent alignment is the physical basis for Mendel's Law of Independent Assortment." },

  { id: 179, topic: "Chromosomal Theory of Inheritance", q: "<b>Assertion (A):</b> Mendel's contemporaries did not accept the concept of stable, discrete, non-blending factors.<br><b>Reason (R):</b> The apparently continuous variation seen in nature contradicted the idea of discrete factors.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states Mendel's concept of 'factors as stable and discrete units... which did not blend with each other, was not accepted by his contemporaries as an explanation for the apparently continuous variation seen in nature.' The continuous variation (R) was the reason for rejection (A)." },

  { id: 180, topic: "Chromosomal Theory of Inheritance", q: "Select the correct chronological order:", options: ["Mendel's publication → Rediscovery → Chromosomal theory → Morgan's verification", "Rediscovery → Mendel's publication → Morgan's verification → Chromosomal theory", "Chromosomal theory → Mendel's publication → Rediscovery → Morgan's verification", "Mendel's publication → Morgan's verification → Rediscovery → Chromosomal theory"], correct: 0, explanation: "Correct chronology: Mendel's publication (1865) → Rediscovery by de Vries, Correns, von Tschermak (1900) → Chromosomal theory by Sutton & Boveri (~1902) → Experimental verification by Morgan. This sequence is explicitly described in NCERT." },

  // ───── TOPIC: LINKAGE AND RECOMBINATION ─────
  { id: 181, topic: "Linkage and Recombination", q: "Morgan observed that in his dihybrid crosses in <i>Drosophila</i>, the F<sub>2</sub> ratio:", options: ["Was exactly 9:3:3:1", "Deviated very significantly from 9:3:3:1", "Was exactly 3:1", "Showed only two phenotypic classes"], correct: 1, explanation: "NCERT states: 'He observed that the two genes did not segregate independently of each other and the F2 ratio deviated very significantly from the 9:3:3:1 ratio.' This deviation was due to linkage — genes on the same chromosome." },

  { id: 182, topic: "Linkage and Recombination", q: "The term <b>linkage</b> was coined by:", options: ["Gregor Mendel", "Alfred Sturtevant", "Thomas Hunt Morgan", "Walter Sutton"], correct: 2, explanation: "NCERT states: 'Morgan attributed this due to the physical association or linkage of the two genes and coined the term linkage to describe this physical association of genes on a chromosome.' Morgan coined BOTH the terms 'linkage' and 'recombination.'" },

  { id: 183, topic: "Linkage and Recombination", q: "Linkage is defined as:", options: ["The generation of non-parental gene combinations", "The physical association of genes on the same chromosome", "The independent segregation of genes on different chromosomes", "The blending of alleles during gamete formation"], correct: 1, explanation: "NCERT defines linkage as 'the physical association of genes on a chromosome.' Recombination is the generation of non-parental gene combinations (option A). Linked genes tend to be inherited together, unlike independently assorting genes." },

  { id: 184, topic: "Linkage and Recombination", q: "Recombination refers to:", options: ["Physical association of genes on the same chromosome", "Segregation of alleles during meiosis", "Generation of non-parental gene combinations", "Duplication of genes before cell division"], correct: 2, explanation: "NCERT defines recombination as 'the generation of non-parental gene combinations.' When linked genes undergo crossing over during meiosis, new (non-parental) combinations of alleles are produced in some gametes." },

  { id: 185, topic: "Linkage and Recombination", q: "When two genes in a dihybrid cross are located on the <b>same chromosome</b>, the proportion of parental gene combinations is:", options: ["Equal to non-parental combinations", "Much lower than non-parental combinations", "Much higher than non-parental combinations", "Zero"], correct: 2, explanation: "NCERT states: 'when the two genes in a dihybrid cross were situated on the same chromosome, the proportion of parental gene combinations were much higher than the non-parental type.' This is because linked genes tend to be inherited together." },

  { id: 186, topic: "Linkage and Recombination", q: "Morgan hybridised which of the following in his dihybrid cross?", options: ["Yellow-bodied, red-eyed females × Brown-bodied, white-eyed males", "Yellow-bodied, white-eyed females × Brown-bodied, red-eyed males", "Brown-bodied, white-eyed females × Yellow-bodied, red-eyed males", "Brown-bodied, red-eyed females × Yellow-bodied, white-eyed males"], correct: 1, explanation: "NCERT states: 'Morgan hybridised yellow-bodied, white-eyed females to brown-bodied, red-eyed males.' The specific combination of traits in each parent must be remembered precisely for NEET." },

  { id: 187, topic: "Linkage and Recombination", q: "<b>Assertion (A):</b> Tightly linked genes show very low recombination frequency.<br><b>Reason (R):</b> Tightly linked genes are located very close to each other on the same chromosome.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. Tightly linked genes show very low recombination (A) because they are located close together on the same chromosome, making crossing over between them less likely (R). The closer the genes, the less frequently recombination occurs between them." },

  { id: 188, topic: "Linkage and Recombination", q: "The recombination frequency between genes <b>white</b> and <b>yellow</b> in <i>Drosophila</i> is:", options: ["37.2 per cent", "1.3 per cent", "50 per cent", "0 per cent"], correct: 1, explanation: "NCERT states: 'the genes white and yellow were very tightly linked and showed only 1.3 per cent recombination.' 37.2% is the recombination between white and miniature wing (loosely linked). These specific values are frequently asked in NEET." },

  { id: 189, topic: "Linkage and Recombination", q: "The recombination frequency between genes <b>white</b> and <b>miniature wing</b> in <i>Drosophila</i> is:", options: ["1.3 per cent", "50 per cent", "37.2 per cent", "0 per cent"], correct: 2, explanation: "NCERT states: 'white and miniature wing showed 37.2 per cent recombination.' This indicates loose linkage — the genes are farther apart on the same chromosome compared to white and yellow (1.3%)." },

  { id: 190, topic: "Linkage and Recombination", q: "Which genes in <i>Drosophila</i> are <b>more tightly linked</b>?", options: ["White and miniature wing (37.2% recombination)", "White and yellow (1.3% recombination)", "Both are equally linked", "Neither shows linkage"], correct: 1, explanation: "Lower recombination frequency = tighter linkage = genes closer together. White and yellow (1.3%) are much more tightly linked than white and miniature wing (37.2%). Recombination frequency is inversely proportional to tightness of linkage." },

  { id: 191, topic: "Linkage and Recombination", q: "Alfred Sturtevant used <b>recombination frequency</b> between gene pairs to:", options: ["Discover new mutations in Drosophila", "Prove the Law of Independent Assortment", "Measure the distance between genes and map their positions on chromosomes", "Count the total number of genes in Drosophila"], correct: 2, explanation: "NCERT states: 'Alfred Sturtevant used the frequency of recombination between gene pairs on the same chromosome as a measure of the distance between genes and mapped their position on the chromosome.' Higher recombination = greater distance." },

  { id: 192, topic: "Linkage and Recombination", q: "Genetic maps prepared by Sturtevant's method were later used as a starting point in:", options: ["Mendel's hybridisation experiments", "Discovery of DNA structure", "Whole genome sequencing projects like Human Genome Project", "Discovery of cell division"], correct: 2, explanation: "NCERT states: 'Today genetic maps are extensively used as a starting point in the sequencing of whole genomes as was done in the case of the Human Genome Sequencing Project.'" },

  { id: 193, topic: "Linkage and Recombination", q: "Select the <b>incorrect</b> statement about linkage:", options: ["Linked genes are located on the same chromosome", "Linkage leads to deviation from the 9:3:3:1 ratio", "Parental gene combinations are less frequent than recombinant types in linked genes", "Tightly linked genes show very low recombination"], correct: 2, explanation: "NCERT states parental gene combinations are MUCH HIGHER (not less) than non-parental types when genes are linked. Linked genes tend to be inherited together, so parental combinations dominate. Option C reverses this — a classic NEET trap." },

  { id: 194, topic: "Linkage and Recombination", q: "<b>Assertion (A):</b> Morgan's F<sub>2</sub> ratio in dihybrid crosses with <i>Drosophila</i> deviated from 9:3:3:1.<br><b>Reason (R):</b> The genes Morgan studied were located on the same chromosome and did not assort independently.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. The deviation from 9:3:3:1 (A) occurred because the genes were located on the same chromosome (X chromosome) and therefore did not segregate independently — they were linked (R). R directly explains the cause of the observed deviation." },

  { id: 195, topic: "Linkage and Recombination", q: "Consider the following statements:<br>(i) Linkage violates the Law of Independent Assortment<br>(ii) Recombination frequency is directly proportional to the distance between genes<br>(iii) Sturtevant was Morgan's student<br>(iv) Morgan coined the terms linkage and recombination<br>Which of the above are correct?", options: ["(i) and (ii) only", "(i), (ii) and (iii) only", "(i), (ii), (iii) and (iv)", "(ii) and (iv) only"], correct: 2, explanation: "All four statements are correct per NCERT. (i) Linked genes don't assort independently — violating independent assortment. (ii) Greater distance = more recombination (Sturtevant's basis for mapping). (iii) NCERT says 'His student Alfred Sturtevant.' (iv) NCERT says Morgan 'coined the term linkage... and the term recombination.'" },

  // ───── TOPIC: POLYGENIC INHERITANCE ─────
  { id: 196, topic: "Polygenic Inheritance", q: "Polygenic traits are controlled by:", options: ["A single gene with two alleles", "Two genes only", "Three or more genes", "Multiple alleles of a single gene"], correct: 2, explanation: "NCERT states: 'Such traits are generally controlled by three or more genes and are thus called as polygenic traits.' This is different from multiple allelism (many alleles of ONE gene) or monogenic traits (single gene). The key threshold is THREE or more genes." },

  { id: 197, topic: "Polygenic Inheritance", q: "Which of the following is a classic example of polygenic inheritance in humans?", options: ["ABO blood grouping", "Sickle cell anaemia", "Skin colour", "Phenylketonuria"], correct: 2, explanation: "NCERT states: 'Human skin colour is another classic example for this.' ABO blood grouping is an example of multiple allelism/codominance. Sickle cell anaemia and PKU are single gene disorders. Skin colour is controlled by multiple genes with additive effects." },

  { id: 198, topic: "Polygenic Inheritance", q: "In polygenic inheritance, the effect of each allele is:", options: ["Dominant over the other", "Recessive to the other", "Additive", "Epistatic"], correct: 2, explanation: "NCERT states: 'In a polygenic trait the phenotype reflects the contribution of each allele, i.e., the effect of each allele is additive.' Unlike Mendelian dominance where one allele masks the other, in polygenic traits each allele adds to the phenotype." },

  { id: 199, topic: "Polygenic Inheritance", q: "If three genes (A, B, C) control skin colour, the <b>darkest</b> skin colour would be found in the genotype:", options: ["aabbcc", "AaBbCc", "AABBCC", "AABbCc"], correct: 2, explanation: "NCERT states: 'The genotype with all the dominant alleles (AABBCC) will have the darkest skin colour.' Since dominant alleles A, B, C contribute to dark skin colour additively, having all six dominant alleles gives the maximum darkness." },

  { id: 200, topic: "Polygenic Inheritance", q: "If three genes (A, B, C) control skin colour, the <b>lightest</b> skin colour would be found in the genotype:", options: ["AABBCC", "AaBbCc", "AAbbcc", "aabbcc"], correct: 3, explanation: "NCERT states: 'that with all the recessive alleles (aabbcc) will have the lightest skin colour.' Since recessive alleles (a, b, c) contribute to light skin, having all six recessive alleles gives the lightest colour." },

  { id: 201, topic: "Polygenic Inheritance", q: "The genotype with three dominant alleles and three recessive alleles (e.g., AaBbCc) for skin colour will have:", options: ["The darkest skin colour", "The lightest skin colour", "An intermediate skin colour", "No skin pigmentation"], correct: 2, explanation: "NCERT states: 'the genotype with three dominant alleles and three recessive alleles will have an intermediate skin colour.' This demonstrates the additive nature — each dominant allele adds equally to the darkness." },

  { id: 202, topic: "Polygenic Inheritance", q: "<b>Assertion (A):</b> Polygenic inheritance differs from Mendelian inheritance in the pattern of trait expression.<br><b>Reason (R):</b> Mendelian traits show distinct alternate forms while polygenic traits are spread across a gradient.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT contrasts Mendel's traits (distinct alternate forms like purple/white) with polygenic traits (spread across a gradient, e.g., continuous range of heights). This difference in trait expression pattern (R) is precisely what distinguishes polygenic from Mendelian inheritance (A)." },

  { id: 203, topic: "Polygenic Inheritance", q: "Besides involvement of multiple genes, polygenic inheritance also takes into account:", options: ["Influence of cytoplasm", "Influence of environment", "Effect of mutations only", "Influence of mitochondrial DNA"], correct: 1, explanation: "NCERT states: 'Besides the involvement of multiple genes polygenic inheritance also takes into account the influence of environment.' This is why polygenic traits show continuous variation — both genetic and environmental factors contribute." },

  { id: 204, topic: "Polygenic Inheritance", q: "Select the <b>incorrect</b> statement about polygenic inheritance:", options: ["The traits show continuous variation across a gradient", "Three or more genes are involved", "Each allele has an additive effect on the phenotype", "Only one gene with multiple alleles controls the trait"], correct: 3, explanation: "Option D describes multiple allelism (e.g., ABO blood groups — one gene, multiple alleles), NOT polygenic inheritance. Polygenic inheritance involves three or MORE genes (each with their own alleles) collectively controlling a single trait." },

  { id: 205, topic: "Polygenic Inheritance", q: "Consider the following:<br>(i) Human height<br>(ii) Human skin colour<br>(iii) ABO blood group<br>(iv) Flower colour in Mendel's pea<br>Which of the above are examples of polygenic traits?", options: ["(i) and (ii) only", "(i), (ii) and (iii)", "(i), (ii), (iii) and (iv)", "(ii) and (iv) only"], correct: 0, explanation: "NCERT mentions human height (range of possible heights, not just tall/short) and human skin colour as polygenic traits. ABO blood group is controlled by one gene with multiple alleles (not polygenic). Flower colour in pea was a Mendelian trait with distinct forms." },

  { id: 206, topic: "Polygenic Inheritance", q: "In the polygenic model for skin colour, the number of each type of allele in the genotype determines:", options: ["The blood group of the individual", "The height of the individual", "The darkness or lightness of the skin", "The enzyme efficiency in the individual"], correct: 2, explanation: "NCERT states: 'the number of each type of alleles in the genotype would determine the darkness or lightness of the skin in an individual.' More dominant alleles = darker; more recessive alleles = lighter." },

  { id: 207, topic: "Polygenic Inheritance", q: "Which of the following genotypes would produce a <b>darker</b> skin colour than AaBbCc?", options: ["Aabbcc", "aaBbCc", "AABbCc", "aabbcc"], correct: 2, explanation: "AaBbCc has 3 dominant + 3 recessive alleles (intermediate). AABbCc has 4 dominant + 2 recessive alleles, so it produces darker skin. Aabbcc has 1 dominant + 5 recessive (lighter). aaBbCc has 2 dominant + 4 recessive (lighter). aabbcc is the lightest." },

  { id: 208, topic: "Polygenic Inheritance", q: "<b>Assertion (A):</b> Human height shows a whole range of possible variations rather than just two distinct alternatives.<br><b>Reason (R):</b> Human height is a polygenic trait controlled by three or more genes along with environmental influence.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states 'we don't just have tall or short people as two distinct alternatives but a whole range of possible heights' (A). This continuous range exists because height is a polygenic trait controlled by multiple genes plus environmental influence (R). R correctly explains why A is observed." },

  { id: 209, topic: "Polygenic Inheritance", q: "Which of the following correctly differentiates <b>polygenic inheritance</b> from <b>multiple allelism</b>?", options: ["Polygenic inheritance involves many alleles of one gene; multiple allelism involves many genes", "Polygenic inheritance involves three or more genes controlling one trait; multiple allelism involves more than two alleles of one gene", "Both are the same concept", "Polygenic inheritance shows distinct traits; multiple allelism shows continuous variation"], correct: 1, explanation: "Polygenic inheritance = many genes (3+) → one trait (e.g., skin colour by genes A, B, C). Multiple allelism = one gene → many alleles (e.g., ABO has 3 alleles of gene I). Option A reverses the definitions. Option D also reverses — polygenic shows continuous variation, not distinct." },

  { id: 210, topic: "Polygenic Inheritance", q: "Mendel's studies mainly described traits that have:", options: ["Continuous variation spread across a gradient", "Distinct alternate forms", "Additive effects of multiple genes", "Environmental influence on expression"], correct: 1, explanation: "NCERT states: 'Mendel's studies mainly described those traits that have distinct alternate forms such as flower colour which are either purple or white.' Continuous variation, additive effects, and environmental influence describe polygenic traits — not Mendelian traits." },

  { id: 211, topic: "Polygenic Inheritance", q: "If skin colour is controlled by 3 genes (A, B, C) with additive effects, how many classes of skin colour are possible in the F<sub>2</sub> generation of a cross between AABBCC × aabbcc?", options: ["3", "5", "7", "9"], correct: 2, explanation: "With 3 genes, the number of dominant alleles can range from 0 (aabbcc) to 6 (AABBCC), giving 7 phenotypic classes (0, 1, 2, 3, 4, 5, 6 dominant alleles). Formula: 2n + 1 where n = number of gene pairs. So 2(3) + 1 = 7 classes." },

  { id: 212, topic: "Polygenic Inheritance", q: "<b>Assertion (A):</b> Polygenic traits show continuous variation in a population.<br><b>Reason (R):</b> Environmental factors have no role in polygenic inheritance.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 2, explanation: "Assertion is TRUE — polygenic traits show continuous variation (gradient). Reason is FALSE — NCERT states: 'Besides the involvement of multiple genes polygenic inheritance also takes into account the influence of environment.' Environment DOES play a role and contributes to the continuous variation." },

  // ───── TOPIC: PLEIOTROPY ─────
  { id: 213, topic: "Pleiotropy", q: "A pleiotropic gene is one that:", options: ["Controls only one phenotypic trait", "Is controlled by multiple genes", "Exhibits multiple phenotypic expression", "Has multiple alleles in the population"], correct: 2, explanation: "NCERT states: 'There are however instances where a single gene can exhibit multiple phenotypic expression. Such a gene is called a pleiotropic gene.' One gene → many phenotypic effects. This is the opposite of polygenic inheritance (many genes → one trait)." },

  { id: 214, topic: "Pleiotropy", q: "The underlying mechanism of pleiotropy in most cases is:", options: ["The effect of multiple genes on a single trait", "The effect of a gene on metabolic pathways which contribute towards different phenotypes", "Environmental influence on gene expression", "Codominance between two alleles"], correct: 1, explanation: "NCERT states: 'The underlying mechanism of pleiotropy in most cases is the effect of a gene on metabolic pathways which contribute towards different phenotypes.' A single gene product affects a metabolic pathway that branches into multiple phenotypic outcomes." },

  { id: 215, topic: "Pleiotropy", q: "Phenylketonuria (PKU) is caused by mutation in the gene that codes for:", options: ["Tyrosinase", "Phenylalanine hydroxylase", "Lactase", "Hexosaminidase"], correct: 1, explanation: "NCERT states: 'The disease is caused by mutation in the gene that codes for the enzyme phenyl alanine hydroxylase (single gene mutation).' Students often confuse this with tyrosinase (related to albinism). PKU specifically involves phenylalanine hydroxylase." },

  { id: 216, topic: "Pleiotropy", q: "Phenylketonuria manifests through:<br>(i) Mental retardation<br>(ii) Reduction in hair pigmentation<br>(iii) Reduction in skin pigmentation<br>(iv) Increased stature", options: ["(i), (ii) and (iii) only", "(i) and (iv) only", "(ii) and (iii) only", "(i), (ii), (iii) and (iv)"], correct: 0, explanation: "NCERT states PKU 'manifests itself through phenotypic expression characterised by mental retardation and a reduction in hair and skin pigmentation.' Statement (iv) — increased stature — is NOT a symptom of PKU. Three phenotypic effects from one gene mutation = pleiotropy." },

  { id: 217, topic: "Pleiotropy", q: "<b>Assertion (A):</b> Phenylketonuria is an example of pleiotropy.<br><b>Reason (R):</b> A single gene mutation in phenylalanine hydroxylase causes both mental retardation and reduction in pigmentation.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. PKU is a pleiotropic condition (A) because ONE gene mutation produces MULTIPLE phenotypic effects — mental retardation AND reduction in hair and skin pigmentation (R). R demonstrates exactly why PKU qualifies as an example of pleiotropy." },

  { id: 218, topic: "Pleiotropy", q: "Which of the following correctly describes the relationship between <b>polygenic inheritance</b> and <b>pleiotropy</b>?", options: ["Both involve many genes affecting one trait", "Both involve one gene affecting many traits", "Polygenic = many genes → one trait; Pleiotropy = one gene → many traits", "Polygenic = one gene → many traits; Pleiotropy = many genes → one trait"], correct: 2, explanation: "Polygenic inheritance = many genes controlling ONE trait (e.g., skin colour by genes A, B, C). Pleiotropy = ONE gene affecting MANY traits (e.g., PKU gene affecting brain function and pigmentation). They are conceptually opposite. Option D reverses the two — a very common NEET trap." },

  { id: 219, topic: "Pleiotropy", q: "Select the <b>incorrect</b> statement about phenylketonuria:", options: ["It is caused by a single gene mutation", "The affected enzyme is phenylalanine hydroxylase", "It is an example of polygenic inheritance", "It shows multiple phenotypic expressions"], correct: 2, explanation: "PKU is an example of PLEIOTROPY (not polygenic inheritance). It involves a SINGLE gene mutation affecting MULTIPLE phenotypes. Polygenic inheritance involves many genes for one trait — the exact opposite. This is the most frequently tested confusion in NEET between pleiotropy and polygenic inheritance." },

  { id: 220, topic: "Pleiotropy", q: "In phenylketonuria, the reduction in hair and skin pigmentation occurs due to:", options: ["Direct mutation in the gene for pigmentation", "Effect of the mutated gene on metabolic pathways contributing to different phenotypes", "Polygenic control of pigmentation", "Codominance between pigmentation alleles"], correct: 1, explanation: "NCERT states the mechanism of pleiotropy is 'the effect of a gene on metabolic pathways which contribute towards different phenotypes.' In PKU, the single mutated phenylalanine hydroxylase gene affects metabolic pathways that influence BOTH brain function and pigmentation — not a separate pigmentation gene mutation." },

  // ───── TOPIC: SEX DETERMINATION ─────
  { id: 221, topic: "Sex Determination", q: "The 'X body' was first observed by:", options: ["T.H. Morgan in 1910", "Henking in 1891", "Sutton in 1902", "Boveri in 1902"], correct: 1, explanation: "NCERT states: 'Henking (1891) could trace a specific nuclear structure all through spermatogenesis in a few insects.' He named it the 'X body.' He observed it but could not explain its significance. It was later identified as a chromosome." },

  { id: 222, topic: "Sex Determination", q: "Henking observed the 'X body' during the process of:", options: ["Oogenesis in insects", "Mitosis in plants", "Spermatogenesis in insects", "Fertilisation in mammals"], correct: 2, explanation: "NCERT states: 'Henking (1891) could trace a specific nuclear structure all through spermatogenesis in a few insects.' The observation was specifically during sperm formation, not oogenesis or mitosis." },

  { id: 223, topic: "Sex Determination", q: "After spermatogenesis, the distribution of the X body in sperm was:", options: ["All sperm received the X body", "No sperm received the X body", "50% sperm received it and 50% did not", "75% sperm received it and 25% did not"], correct: 2, explanation: "NCERT states: '50 per cent of the sperm received this structure after spermatogenesis, whereas the other 50 per cent sperm did not receive it.' This 50:50 distribution is the basis for 1:1 sex ratio." },

  { id: 224, topic: "Sex Determination", q: "Which of the following is correct about Henking's discovery?", options: ["He named the structure 'X chromosome' and explained its role in sex determination", "He named the structure 'X body' but could not explain its significance", "He named the structure 'Y body' and linked it to maleness", "He identified the structure as an autosome"], correct: 1, explanation: "NCERT states: 'Henking gave a name to this structure as the X body but he could not explain its significance.' It was later scientists who identified it as a chromosome and linked it to sex determination. This distinction is a key NEET fact." },

  { id: 225, topic: "Sex Determination", q: "Grasshopper shows which type of sex determination mechanism?", options: ["XY type", "XO type", "ZW type", "ZO type"], correct: 1, explanation: "NCERT states: 'Grasshopper is an example of XO type of sex determination in which the males have only one X-chromosome besides the autosomes, whereas females have a pair of X-chromosomes.' Grasshopper = XO type is one of the most asked facts in NEET." },

  { id: 226, topic: "Sex Determination", q: "In the XO type of sex determination, the males have:", options: ["A pair of X-chromosomes", "One X and one Y chromosome", "Only one X-chromosome besides autosomes", "A pair of Y-chromosomes"], correct: 2, explanation: "NCERT states: 'males have only one X-chromosome besides the autosomes, whereas females have a pair of X-chromosomes.' Males are XO (missing the second sex chromosome), females are XX." },

  { id: 227, topic: "Sex Determination", q: "In XO type sex determination, the total number of chromosomes in males and females is:", options: ["Equal in both", "More in males", "More in females", "Cannot be determined"], correct: 2, explanation: "In XO type, females have XX + autosomes while males have only X + autosomes (one less chromosome). NCERT hints at this by asking: 'Do you think the number of chromosomes in the male and female are equal?' — implying they are NOT equal in XO type." },

  { id: 228, topic: "Sex Determination", q: "<b>Assertion (A):</b> In XY type of sex determination, both males and females have the same number of chromosomes.<br><b>Reason (R):</b> Males have XY and females have XX, but both possess the same number of autosomes.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states: 'XY type of sex determination is seen where both male and female have same number of chromosomes' and 'Both males and females bear same number of autosomes.' Males (XY + autosomes) and females (XX + autosomes) have equal total chromosomes. R explains how equal numbers are maintained despite different sex chromosomes." },

  { id: 229, topic: "Sex Determination", q: "The Y-chromosome in XY type sex determination is described as:", options: ["Larger than the X-chromosome", "Identical to the X-chromosome", "Distinctly smaller than the X-chromosome", "Absent in all somatic cells"], correct: 2, explanation: "NCERT states: 'Among the males an X-chromosome is present but its counter part is distinctly smaller and called the Y-chromosome.' The Y chromosome is physically smaller than X — this size difference is frequently tested." },

  { id: 230, topic: "Sex Determination", q: "Which of the following correctly describes <b>male heterogamety</b>?", options: ["Females produce two different types of gametes in terms of sex chromosomes", "Males produce two different types of gametes in terms of sex chromosomes", "Both males and females produce identical gametes", "Only autosomes are involved in gamete formation"], correct: 1, explanation: "NCERT states: 'males produce two different types of gametes, (a) either with or without X-chromosome or (b) some gametes with X-chromosome and some with Y-chromosome. Such types of sex determination mechanism is designated to be the example of male heterogamety.'" },

  { id: 231, topic: "Sex Determination", q: "Male heterogamety is seen in:<br>(i) Humans<br>(ii) Drosophila<br>(iii) Birds<br>(iv) Grasshopper", options: ["(i) and (ii) only", "(i), (ii) and (iv) only", "(iii) only", "(i), (ii), (iii) and (iv)"], correct: 1, explanation: "Humans (XY), Drosophila (XY), and Grasshopper (XO) all show male heterogamety — males produce two types of gametes. Birds show FEMALE heterogamety (ZW system — females produce two types). This is a classic NEET trap." },

  { id: 232, topic: "Sex Determination", q: "Female heterogamety is observed in:", options: ["Humans", "Drosophila", "Grasshopper", "Birds"], correct: 3, explanation: "NCERT states: 'In some other organisms, e.g., birds, a different mechanism of sex determination is observed... two different types of gametes in terms of the sex chromosomes, are produced by females, i.e., female heterogamety.' In birds, females (ZW) produce two types of gametes (Z and W)." },

  { id: 233, topic: "Sex Determination", q: "In birds, the sex chromosomes are designated as:", options: ["X and Y", "X and O", "Z and W", "A and B"], correct: 2, explanation: "NCERT states: 'the two different sex chromosomes of a female bird has been designated to be the Z and W chromosomes.' The ZW system was named differently from XY 'in order to have a distinction with the mechanism of sex determination described earlier.'" },

  { id: 234, topic: "Sex Determination", q: "In the ZW-ZZ type of sex determination, the males have:", options: ["One Z and one W chromosome", "A pair of W chromosomes", "A pair of Z-chromosomes", "Only one Z chromosome"], correct: 2, explanation: "NCERT states: 'males have a pair of Z-chromosomes besides the autosomes.' Males are ZZ (homogametic) and females are ZW (heterogametic) in birds. This is the REVERSE of the XY system where males are heterogametic." },

  { id: 235, topic: "Sex Determination", q: "In the ZW-ZZ type of sex determination, which sex produces two different types of gametes?", options: ["Males", "Females", "Both males and females", "Neither sex"], correct: 1, explanation: "In ZW-ZZ system, females (ZW) produce two types of gametes — one with Z and one with W. Males (ZZ) produce only one type of gamete with Z. Hence FEMALES are heterogametic. This is opposite to the XY system." },

  { id: 236, topic: "Sex Determination", q: "Select the <b>incorrect</b> statement regarding sex determination:", options: ["In XO type, males have one less chromosome than females", "In XY type, males and females have equal number of chromosomes", "In birds, males are heterogametic (ZW)", "Grasshopper follows the XO type mechanism"], correct: 2, explanation: "In birds, FEMALES are heterogametic (ZW), NOT males. Males in birds are homogametic (ZZ). Option C is incorrect. All other statements are correct per NCERT. This reversal of heterogamety in birds vs mammals is the most tested trap." },

  { id: 237, topic: "Sex Determination", q: "<b>Assertion (A):</b> In the XO type, eggs fertilised by sperm having an X-chromosome become females.<br><b>Reason (R):</b> Females in XO type have a pair of X-chromosomes while males have only one.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states: 'Eggs fertilised by sperm having an X-chromosome become females.' This is because when X-bearing egg + X-bearing sperm combine, the offspring gets XX = female (R). When egg (X) + sperm (no X), offspring gets XO = male. R explains the chromosomal basis for A." },

  { id: 238, topic: "Sex Determination", q: "In XO type sex determination, what determines the sex of the offspring?", options: ["The type of egg produced by the female", "The type of sperm produced by the male", "Environmental temperature", "The number of autosomes"], correct: 1, explanation: "In XO type (male heterogamety), males produce two types of sperm — with X or without X. All eggs have X. So it is the SPERM that determines whether the offspring is XX (female) or XO (male). The father determines sex in male heterogamety systems." },

  { id: 239, topic: "Sex Determination", q: "In birds, which parent determines the sex of the offspring?", options: ["Father (male)", "Mother (female)", "Both equally", "Environment"], correct: 1, explanation: "In birds (ZW-ZZ system), females are heterogametic (ZW) producing two types of eggs — Z-bearing and W-bearing. Males (ZZ) produce only Z-bearing sperm. So the mother determines the sex: Z egg + Z sperm = ZZ (male); W egg + Z sperm = ZW (female)." },

  { id: 240, topic: "Sex Determination", q: "Which of the following pairs is correctly matched?", options: ["Grasshopper — XY type", "Birds — Male heterogamety", "Drosophila — XY type", "Humans — XO type"], correct: 2, explanation: "NCERT states: 'In human beings and in Drosophila the males have one X and one Y chromosome, whereas females have a pair of X-chromosomes besides autosomes.' So Drosophila = XY type ✓. Grasshopper = XO (not XY). Birds = female heterogamety (not male). Humans = XY (not XO)." },

  { id: 241, topic: "Sex Determination", q: "Consider the following organisms and their sex determination types:<br>(i) Grasshopper — XO type<br>(ii) Human — XY type<br>(iii) Drosophila — XY type<br>(iv) Birds — ZW type<br>Which of the above are correctly matched?", options: ["(i) and (ii) only", "(i), (ii) and (iii) only", "(i), (ii), (iii) and (iv)", "(ii) and (iv) only"], correct: 2, explanation: "All four are correctly matched per NCERT. Grasshopper = XO, Human = XY, Drosophila = XY, Birds = ZW. This comprehensive matching question tests all sex determination mechanisms covered in the chapter." },

  { id: 242, topic: "Sex Determination", q: "The term 'autosomes' refers to:", options: ["Sex chromosomes that determine gender", "All chromosomes other than sex chromosomes", "Chromosomes found only in males", "Extra chromosomes in aneuploid organisms"], correct: 1, explanation: "NCERT states: 'Due to the involvement of the X-chromosome in the determination of sex, it was designated to be the sex chromosome, and the rest of the chromosomes were named as autosomes.' Autosomes are all non-sex chromosomes." },

  { id: 243, topic: "Sex Determination", q: "<b>Assertion (A):</b> In XO and XY types, males are heterogametic.<br><b>Reason (R):</b> In both systems, males produce two different types of gametes in terms of sex chromosomes.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT describes male heterogamety in both systems: (a) XO — some sperm with X, some without X; (b) XY — some sperm with X, some with Y. In both cases males produce two different gamete types (R), making them heterogametic (A)." },

  { id: 244, topic: "Sex Determination", q: "In humans, the sex of the child is determined by:", options: ["The mother's egg", "The father's sperm", "The number of autosomes", "Environmental factors"], correct: 1, explanation: "Humans follow XY type (male heterogamety). Males produce two types of sperm (X-bearing and Y-bearing), while females produce only X-bearing eggs. If X-sperm fertilises → XX (girl); if Y-sperm fertilises → XY (boy). The father's sperm determines sex." },

  { id: 245, topic: "Sex Determination", q: "Which of the following correctly differentiates XO type from XY type of sex determination?", options: ["In XO type, males and females have equal chromosomes; in XY type they are unequal", "In XO type, males lack one sex chromosome; in XY type, males have both X and Y", "In XO type, females are heterogametic; in XY type, males are heterogametic", "Both are found exclusively in mammals"], correct: 1, explanation: "In XO: males have only one X (no Y), so they lack one sex chromosome. In XY: males have both X and Y chromosomes. In both types, MALES are heterogametic (not females — option C is wrong for XO). XO is mainly in insects, not mammals (option D wrong)." },

  { id: 246, topic: "Sex Determination", q: "The initial clue about the genetic/chromosomal mechanism of sex determination came from experiments carried out in:", options: ["Mammals", "Birds", "Insects", "Plants"], correct: 2, explanation: "NCERT states: 'The initial clue about the genetic/chromosomal mechanism of sex determination can be traced back to some of the experiments carried out in insects.' Henking's work on spermatogenesis in insects was the starting point." },

  { id: 247, topic: "Sex Determination", q: "In the ZW system, a cross between a male (ZZ) and a female (ZW) would produce offspring in the ratio of:", options: ["All males", "All females", "1 male : 1 female", "3 males : 1 female"], correct: 2, explanation: "ZZ (male) × ZW (female) → ZZ (male) and ZW (female) in equal proportion = 1:1 sex ratio. Father gives Z to all offspring; mother gives Z or W (50:50). Z from mother = ZZ (male); W from mother = ZW (female). Same 1:1 ratio as XY system." },

  { id: 248, topic: "Sex Determination", q: "Select the <b>incorrect</b> statement about the ZW-ZZ system of sex determination:", options: ["Females have one Z and one W chromosome", "Males have a pair of Z-chromosomes", "Males are heterogametic in this system", "This system is observed in birds"], correct: 2, explanation: "In ZW-ZZ system, FEMALES (ZW) are heterogametic — they produce two types of gametes (Z and W). MALES (ZZ) are homogametic — they produce only Z-bearing gametes. Option C incorrectly states males are heterogametic. This is the OPPOSITE of the XY system and a very common NEET trap." },

  { id: 249, topic: "Sex Determination", q: "Consider the following:<br>(A) Male heterogamety — Father determines sex of offspring<br>(B) Female heterogamety — Mother determines sex of offspring<br>(C) XO type — Males produce gametes with and without X<br>(D) ZW type — Males produce gametes with Z and W<br>Which of the above are correct?", options: ["(A), (B), (C) and (D)", "(A), (B) and (C) only", "(A) and (C) only", "(B) and (D) only"], correct: 1, explanation: "Statement (D) is INCORRECT — in ZW type, FEMALES (not males) produce gametes with Z and W. Males (ZZ) produce only Z-bearing gametes. Statements A, B, and C are all correct. In male heterogamety, father determines sex; in female heterogamety, mother determines sex." },

  { id: 250, topic: "Sex Determination", q: "<b>Assertion (A):</b> The ZW-ZZ system was designated with different letters (Z, W) instead of X and Y.<br><b>Reason (R):</b> This distinction was made because in the ZW system, females are heterogametic, which is opposite to the XY system.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states: 'In order to have a distinction with the mechanism of sex determination described earlier, the two different sex chromosomes of a female bird has been designated to be the Z and W chromosomes.' The different naming (Z, W vs X, Y) was specifically to distinguish female heterogamety from male heterogamety (R explains A)." },

  // ───── TOPIC: SEX DETERMINATION IN HUMANS ─────
  { id: 251, topic: "Sex Determination in Humans", q: "In humans, the total number of pairs of autosomes is:", options: ["23", "22", "44", "46"], correct: 1, explanation: "NCERT states: 'Out of 23 pairs of chromosomes present, 22 pairs are exactly same in both males and females; these are the autosomes.' Total = 23 pairs, of which 22 pairs are autosomes and 1 pair is sex chromosomes. 44 and 46 refer to number of chromosomes, not pairs." },

  { id: 252, topic: "Sex Determination in Humans", q: "The sex of a child is determined by:", options: ["The genetic makeup of the ovum", "The number of autosomes", "The genetic makeup of the sperm", "Environmental factors during pregnancy"], correct: 2, explanation: "NCERT states: 'it is the genetic makeup of the sperm that determines the sex of the child.' Females produce only X-bearing ova, while males produce X-bearing and Y-bearing sperm (50% each). Whether X or Y sperm fertilises the egg determines the child's sex." },

  { id: 253, topic: "Sex Determination in Humans", q: "During spermatogenesis in human males, the types of sperm produced are:", options: ["All sperm carry X-chromosome", "All sperm carry Y-chromosome", "50% carry X-chromosome and 50% carry Y-chromosome", "75% carry X-chromosome and 25% carry Y-chromosome"], correct: 2, explanation: "NCERT states: '50 per cent of the total sperm produced carry the X-chromosome and the rest 50 per cent has Y-chromosome besides the autosomes.' This equal distribution ensures a 1:1 sex ratio." },

  { id: 254, topic: "Sex Determination in Humans", q: "Human females produce:", options: ["Two types of ova — one with X and one with Y", "Two types of ova — one with X and one without any sex chromosome", "Only one type of ovum with an X-chromosome", "Only one type of ovum with a Y-chromosome"], correct: 2, explanation: "NCERT states: 'Females, however, produce only one type of ovum with an X-chromosome.' This makes females homogametic (XX), and all their eggs carry one X chromosome." },

  { id: 255, topic: "Sex Determination in Humans", q: "If an ovum is fertilised by a sperm carrying a <b>Y-chromosome</b>, the offspring will be:", options: ["Female (XX)", "Male (XY)", "Female (XY)", "Male (XX)"], correct: 1, explanation: "NCERT states: 'the fertilisation of ovum with Y-chromosome carrying sperm results into a male offspring.' Ovum (X) + Sperm (Y) = XY = Male. If X-sperm fertilises → XX = Female." },

  { id: 256, topic: "Sex Determination in Humans", q: "The probability of a male or female child in each pregnancy is:", options: ["75% male and 25% female", "25% male and 75% female", "50% male and 50% female", "It depends on the mother's genotype"], correct: 2, explanation: "NCERT states: 'in each pregnancy there is always 50 per cent probability of either a male or a female child.' Since X and Y sperm are produced in equal proportion and there is equal probability of fertilisation, the sex ratio is always 1:1 per pregnancy." },

  { id: 257, topic: "Sex Determination in Humans", q: "<b>Assertion (A):</b> Women should not be blamed for the sex of the child.<br><b>Reason (R):</b> It is the genetic makeup of the sperm from the father that determines the sex of the child.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT explicitly states: 'It is unfortunate that in our society women are blamed for giving birth to female children and have been ostracised and ill-treated because of this false notion.' The father's sperm (X or Y) determines sex (R), so blaming women is scientifically incorrect (A)." },

  { id: 258, topic: "Sex Determination in Humans", q: "The 22 pairs of autosomes in humans are:", options: ["Different in males and females", "Present only in males", "Exactly the same in both males and females", "Present only in somatic cells, not gametes"], correct: 2, explanation: "NCERT states: '22 pairs are exactly same in both males and females; these are the autosomes.' Only the 23rd pair (sex chromosomes) differs — XX in females and XY in males. Autosomes are identical in both sexes." },

  { id: 259, topic: "Sex Determination in Humans", q: "A human male has the sex chromosome constitution:", options: ["XX", "XO", "XY", "ZZ"], correct: 2, explanation: "NCERT states: 'the presence of an X and Y chromosome are determinant of the male characteristic.' Human males = XY. XX = female, XO = seen in grasshopper males or Turner syndrome, ZZ = male birds." },

  { id: 260, topic: "Sex Determination in Humans", q: "Select the <b>incorrect</b> statement about sex determination in humans:", options: ["Humans have 23 pairs of chromosomes", "There is equal probability of fertilisation with X or Y sperm", "The mother's ovum determines the sex of the child", "Males produce two types of sperm in equal proportion"], correct: 2, explanation: "The MOTHER's ovum does NOT determine sex — all ova carry X. It is the FATHER's sperm (X or Y) that determines whether the child is female (XX) or male (XY). NCERT emphasizes: 'it is the genetic makeup of the sperm that determines the sex of the child.'" },

  { id: 261, topic: "Sex Determination in Humans", q: "Consider the following statements:<br>(A) Each pregnancy has a 50% probability of a male child<br>(B) The probability changes if previous children were all females<br>(C) Sex determination depends on which sperm fertilises the ovum<br>(D) Women are responsible for the sex of the child", options: ["(A) and (C) only", "(A), (B) and (C)", "(B) and (D) only", "(A), (C) and (D)"], correct: 0, explanation: "Statements (A) and (C) are correct per NCERT. Statement (B) is wrong — the probability remains 50% in EACH pregnancy regardless of previous outcomes (independent events). Statement (D) is the 'false notion' that NCERT explicitly rejects — 'women are blamed... because of this false notion.'" },

  { id: 262, topic: "Sex Determination in Humans", q: "<b>Assertion (A):</b> In humans, there is an equal probability of fertilisation of the ovum with sperm carrying either X or Y chromosome.<br><b>Reason (R):</b> During spermatogenesis, 50% sperm carry X and 50% carry Y chromosome.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. Equal probability of fertilisation (A) exists because spermatogenesis produces X and Y bearing sperm in equal proportions (R). The 50:50 sperm ratio directly leads to equal fertilisation probability, making R the correct explanation of A." },

  // ───── TOPIC: SEX DETERMINATION IN HONEY BEE ─────
  { id: 263, topic: "Sex Determination in Honey Bee", q: "The sex determination system in honey bee is called:", options: ["XY type", "XO type", "ZW type", "Haplodiploid type"], correct: 3, explanation: "NCERT states: 'This is called as haplodiploid sex-determination system.' It is based on the number of chromosome sets — females are diploid (from fertilised egg) and males are haploid (from unfertilised egg by parthenogenesis)." },

  { id: 264, topic: "Sex Determination in Honey Bee", q: "In honey bee, a male (drone) develops from:", options: ["A fertilised egg", "An unfertilised egg by parthenogenesis", "A diploid zygote", "Union of sperm and egg"], correct: 1, explanation: "NCERT states: 'an unfertilised egg develops as a male (drone) by means of parthenogenesis.' Drones are haploid because they develop without fertilisation. Fertilised eggs develop into females (queen or worker)." },

  { id: 265, topic: "Sex Determination in Honey Bee", q: "In honey bee, the females (queen or worker) are:", options: ["Haploid with 16 chromosomes", "Diploid with 32 chromosomes", "Diploid with 16 chromosomes", "Haploid with 32 chromosomes"], correct: 1, explanation: "NCERT states: 'The females are diploid having 32 chromosomes and males are haploid, i.e., having 16 chromosomes.' Females develop from fertilised eggs (sperm + egg) and are thus diploid." },

  { id: 266, topic: "Sex Determination in Honey Bee", q: "The chromosome number in a drone (male honey bee) is:", options: ["32", "16", "64", "8"], correct: 1, explanation: "NCERT states: 'males are haploid, i.e., having 16 chromosomes.' Drones have half the number of chromosomes compared to females (32). Males = 16 (haploid, n); Females = 32 (diploid, 2n)." },

  { id: 267, topic: "Sex Determination in Honey Bee", q: "In the haplodiploid system, sex determination is based on:", options: ["The type of sex chromosomes present", "The presence or absence of Y chromosome", "The number of sets of chromosomes an individual receives", "Environmental temperature during development"], correct: 2, explanation: "NCERT states: 'The sex determination in honey bee is based on the number of sets of chromosomes an individual receives.' Diploid (2 sets) = female; Haploid (1 set) = male. Unlike XY or ZW systems, there are no specific sex chromosomes involved." },

  { id: 268, topic: "Sex Determination in Honey Bee", q: "In honey bee, males produce sperms by:", options: ["Meiosis", "Mitosis", "Both mitosis and meiosis", "Binary fission"], correct: 1, explanation: "NCERT states that a special characteristic of the haplodiploid system is that 'the males produce sperms by mitosis.' Since males are already haploid (16 chromosomes), they cannot undergo meiosis. Mitosis maintains the haploid number in sperm." },

  { id: 269, topic: "Sex Determination in Honey Bee", q: "<b>Assertion (A):</b> Male honey bees (drones) produce sperm by mitosis, not meiosis.<br><b>Reason (R):</b> Drones are haploid, so meiosis would further reduce the chromosome number to an unviable state.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states males produce sperm by mitosis (A). Since drones are already haploid (n=16), undergoing meiosis would halve chromosomes to 8 — not viable. Mitosis maintains the haploid number. R correctly explains why mitosis is used instead of meiosis." },

  { id: 270, topic: "Sex Determination in Honey Bee", q: "Which of the following is a special characteristic of the haplodiploid sex determination system?", options: ["Males have a father but no grandfather", "Males do not have a father and cannot have sons", "Males have sons but no grandsons", "Males have two fathers"], correct: 1, explanation: "NCERT states: 'males produce sperms by mitosis, they do not have father and thus cannot have sons, but have a grandfather and can have grandsons.' Since drones develop from unfertilised eggs, they have NO father. Their sperm can only produce diploid females — so NO sons." },

  { id: 271, topic: "Sex Determination in Honey Bee", q: "A drone (male honey bee) can have:", options: ["A father and sons", "No father but can have sons", "A grandfather and grandsons", "Neither grandfather nor grandsons"], correct: 2, explanation: "NCERT states drones 'do not have father and thus cannot have sons, but have a grandfather and can have grandsons.' Drone has no father (unfertilised egg) but his mother had a father (grandfather of drone). Drone's sperm → daughter (female) → her unfertilised egg → grandson (drone)." },

  { id: 272, topic: "Sex Determination in Honey Bee", q: "Consider the following about honey bee drones:<br>(i) They develop from unfertilised eggs<br>(ii) They are diploid<br>(iii) They produce sperm by mitosis<br>(iv) They have no father<br>Which statements are correct?", options: ["(i), (ii) and (iii) only", "(i), (iii) and (iv) only", "(ii) and (iv) only", "(i), (ii), (iii) and (iv)"], correct: 1, explanation: "Statement (ii) is INCORRECT — drones are HAPLOID (16 chromosomes), not diploid. They develop from unfertilised eggs by parthenogenesis. Statements (i) unfertilised eggs, (iii) sperm by mitosis, and (iv) no father are all correct per NCERT." },

  { id: 273, topic: "Sex Determination in Honey Bee", q: "In honey bee, a fertilised egg develops into:", options: ["A male (drone)", "A female (queen or worker)", "Either male or female depending on temperature", "A sterile individual only"], correct: 1, explanation: "NCERT states: 'An offspring formed from the union of a sperm and an egg develops as a female (queen or worker).' Fertilisation produces diploid (2n = 32) individuals which are always female. Whether the female becomes queen or worker depends on nutrition (royal jelly), not genetics." },

  { id: 274, topic: "Sex Determination in Honey Bee", q: "Parthenogenesis in honey bee results in the production of:", options: ["Diploid females", "Haploid males", "Diploid males", "Triploid workers"], correct: 1, explanation: "NCERT states: 'an unfertilised egg develops as a male (drone) by means of parthenogenesis.' The unfertilised egg is haploid (n = 16), and since it develops without fertilisation, the resulting drone is also haploid." },

  { id: 275, topic: "Sex Determination in Honey Bee", q: "Select the <b>incorrect</b> statement about the haplodiploid sex determination system:", options: ["Females are diploid and develop from fertilised eggs", "Males are haploid and develop from unfertilised eggs", "Males produce sperm by meiosis to maintain chromosome number", "Males have half the number of chromosomes than females"], correct: 2, explanation: "Males produce sperm by MITOSIS, not meiosis. NCERT explicitly states this as a special characteristic. Since males are already haploid, meiosis is not possible — mitosis produces haploid sperm from haploid cells. All other statements are correct." },

  { id: 276, topic: "Sex Determination in Honey Bee", q: "<b>Assertion (A):</b> A drone honey bee cannot have sons.<br><b>Reason (R):</b> Drone's sperm fertilises the queen's egg, producing only diploid female offspring.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states drones 'cannot have sons.' This is because drone sperm + queen egg = fertilised = diploid = FEMALE (R). Males (drones) only arise from UNFERTILISED eggs, so a drone's sperm can never directly produce a male offspring. R correctly explains A." },

  { id: 277, topic: "Sex Determination in Honey Bee", q: "A drone honey bee has a grandfather because:", options: ["The drone's father mated with the queen", "The drone's mother (queen) developed from a fertilised egg which required a male parent", "Drones inherit chromosomes from both parents", "Grandfathers are always present in all organisms"], correct: 1, explanation: "A drone develops from an unfertilised egg (no father), BUT the queen (his mother) developed from a fertilised egg — meaning the queen had a father. This father of the queen is the drone's grandfather. The grandfather's genes reach the drone through the queen (mother)." },

  { id: 278, topic: "Sex Determination in Honey Bee", q: "Which of the following is the correct comparison between honey bee and human sex determination?", options: ["Both use the XY mechanism", "In humans, sex depends on sperm type; in honey bee, sex depends on fertilisation status", "In both, males are diploid and females are haploid", "Both use the haplodiploid mechanism"], correct: 1, explanation: "In humans (XY type), sex depends on whether X or Y sperm fertilises the egg. In honey bee (haplodiploid), sex depends on whether the egg is fertilised (female) or not (male/drone). Humans are NOT haplodiploid, and in honey bee, males are HAPLOID (not diploid)." },

  { id: 279, topic: "Sex Determination in Honey Bee", q: "Worker bees in a honey bee colony are:", options: ["Haploid males", "Diploid males", "Diploid females", "Haploid females"], correct: 2, explanation: "NCERT states: 'An offspring formed from the union of a sperm and an egg develops as a female (queen or worker).' Workers develop from fertilised eggs and are diploid females (2n = 32). They are females that do not reproduce. Drones (males) are the only haploid individuals." },

  { id: 280, topic: "Sex Determination in Honey Bee", q: "A drone honey bee can have grandsons through the following pathway:", options: ["Drone → son → grandson", "Drone → daughter (fertilised egg) → her unfertilised egg → grandson (drone)", "Drone → unfertilised egg → grandson", "Drone → son → son's unfertilised egg → grandson"], correct: 1, explanation: "Drones cannot have sons (their sperm + egg = female). However: Drone's sperm → fertilises queen's egg → daughter (diploid female). This daughter can lay unfertilised eggs → which develop into drones (grandsons of the original drone). NCERT confirms drones 'can have grandsons' through this indirect route." },

  // ───── TOPIC: MUTATION ─────
  { id: 281, topic: "Mutation", q: "Mutation results in alteration of:", options: ["DNA sequences only without affecting genotype or phenotype", "DNA sequences resulting in changes in genotype and phenotype", "Protein sequences without affecting DNA", "RNA sequences only"], correct: 1, explanation: "NCERT states: 'Mutation is a phenomenon which results in alteration of DNA sequences and consequently results in changes in the genotype and the phenotype of an organism.' Both genotype AND phenotype are affected — not just one." },

  { id: 282, topic: "Mutation", q: "Which of the following phenomena lead to variation in DNA?<br>(i) Recombination<br>(ii) Mutation<br>(iii) Mitosis<br>(iv) Translation", options: ["(i) and (ii) only", "(i), (ii) and (iii)", "(i), (iii) and (iv)", "(i), (ii), (iii) and (iv)"], correct: 0, explanation: "NCERT states: 'In addition to recombination, mutation is another phenomenon that leads to variation in DNA.' Only recombination and mutation are mentioned as sources of DNA variation. Mitosis produces identical copies, and translation is protein synthesis — neither creates DNA variation." },

  { id: 283, topic: "Mutation", q: "In each chromatid, the DNA helix is present in:", options: ["Multiple discontinuous segments", "One continuous helix in highly supercoiled form", "Circular form like in bacteria", "Linear but uncoiled form"], correct: 1, explanation: "NCERT states: 'one DNA helix runs continuously from one end to the other in each chromatid, in a highly supercoiled form.' The DNA is continuous (not segmented) and highly supercoiled within each chromatid." },

  { id: 284, topic: "Mutation", q: "Loss of a segment of DNA from a chromosome is called:", options: ["Insertion", "Duplication", "Deletion", "Inversion"], correct: 2, explanation: "NCERT states: 'loss (deletions) or gain (insertion/duplication) of a segment of DNA, result in alteration in chromosomes.' Deletion = loss of DNA segment. Insertion/Duplication = gain of DNA segment." },

  { id: 285, topic: "Mutation", q: "Gain of a segment of DNA in a chromosome can result from:<br>(i) Insertion<br>(ii) Duplication<br>(iii) Deletion", options: ["(i) only", "(i) and (ii) only", "(iii) only", "(i), (ii) and (iii)"], correct: 1, explanation: "NCERT states: 'loss (deletions) or gain (insertion/duplication) of a segment of DNA.' Gain results from insertion OR duplication. Deletion causes loss, not gain. Both insertion and duplication add DNA segments." },

  { id: 286, topic: "Mutation", q: "Chromosomal aberrations are commonly observed in:", options: ["Normal somatic cells", "Germinal cells during meiosis", "Cancer cells", "Red blood cells"], correct: 2, explanation: "NCERT states: 'Chromosomal aberrations are commonly observed in cancer cells.' This is a direct NCERT statement and a very frequently tested fact. Cancer cells accumulate chromosomal abnormalities due to uncontrolled mutations." },

  { id: 287, topic: "Mutation", q: "A change in a <b>single base pair</b> of DNA is known as:", options: ["Frame-shift mutation", "Chromosomal aberration", "Point mutation", "Deletion mutation"], correct: 2, explanation: "NCERT states: 'mutation also arise due to change in a single base pair of DNA. This is known as point mutation.' Point mutation involves a single base pair change — not a large segment deletion/insertion. This is the most important definition to distinguish from frame-shift." },

  { id: 288, topic: "Mutation", q: "A classical example of point mutation is:", options: ["Down syndrome", "Turner syndrome", "Sickle cell anaemia", "Klinefelter syndrome"], correct: 2, explanation: "NCERT states: 'A classical example of such a mutation is sickle cell anemia.' Sickle cell anaemia results from a single base pair change (point mutation) in the beta-globin gene. Down, Turner, and Klinefelter syndromes are chromosomal disorders, not point mutations." },

  { id: 289, topic: "Mutation", q: "<b>Assertion (A):</b> Sickle cell anaemia is caused by a point mutation.<br><b>Reason (R):</b> Point mutation involves a change in a single base pair of DNA.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT identifies sickle cell anaemia as 'A classical example of such a mutation' (A) and defines point mutation as 'change in a single base pair of DNA' (R). The single base pair change in the beta-globin gene causes sickle cell anaemia, so R correctly explains the nature of mutation in A." },

  { id: 290, topic: "Mutation", q: "Frame-shift mutations are caused by:", options: ["Change in a single base pair", "Deletions and insertions of base pairs of DNA", "Crossing over during meiosis", "Changes in chromosomal number"], correct: 1, explanation: "NCERT states: 'Deletions and insertions of base pairs of DNA, causes frame-shift mutations.' Frame-shift mutations alter the reading frame of the genetic code. A single base pair change (option A) causes point mutation, not frame-shift." },

  { id: 291, topic: "Mutation", q: "Select the <b>incorrect</b> statement about mutations:", options: ["Mutation results in alteration of DNA sequences", "Point mutation involves change in a single base pair", "Sickle cell anaemia is a classical example of frame-shift mutation", "UV radiations can cause mutations"], correct: 2, explanation: "Sickle cell anaemia is a classical example of POINT mutation (not frame-shift). NCERT clearly states: 'A classical example of such a mutation [point mutation] is sickle cell anemia.' This is one of the most frequent NEET traps — confusing point mutation with frame-shift." },

  { id: 292, topic: "Mutation", q: "Chemical and physical factors that induce mutations are called:", options: ["Carcinogens", "Pathogens", "Mutagens", "Allergens"], correct: 2, explanation: "NCERT states: 'there are many chemical and physical factors that induce mutations. These are referred to as mutagens.' While some mutagens can also be carcinogens (cancer-causing), the specific term for mutation-inducing agents is mutagens." },

  { id: 293, topic: "Mutation", q: "Which of the following is an example of a mutagen mentioned in NCERT?", options: ["Infrared radiation", "Visible light", "UV radiation", "Radio waves"], correct: 2, explanation: "NCERT states: 'UV radiations can cause mutations in organisms – it is a mutagen.' UV radiation is the only specific mutagen example mentioned in this section of NCERT. Infrared, visible light, and radio waves are not mentioned as mutagens." },

  { id: 294, topic: "Mutation", q: "Consider the following:<br>(A) Point mutation — Change in single base pair — Sickle cell anaemia<br>(B) Frame-shift mutation — Deletion/Insertion of base pairs — Altered reading frame<br>(C) Chromosomal aberration — Loss/gain of DNA segment — Cancer cells<br>Which of the above are correctly described?", options: ["(A) and (B) only", "(B) and (C) only", "(A) and (C) only", "(A), (B) and (C)"], correct: 3, explanation: "All three are correctly described as per NCERT. Point mutation = single base pair change (e.g., sickle cell anaemia). Frame-shift = deletion/insertion of base pairs. Chromosomal aberration = loss/gain of DNA segments (commonly seen in cancer cells)." },

  { id: 295, topic: "Mutation", q: "<b>Assertion (A):</b> Alteration in chromosomes results in abnormalities or aberrations.<br><b>Reason (R):</b> Genes are located on chromosomes, so any chromosomal change affects the genes.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states: 'Since genes are known to be located on chromosomes, alteration in chromosomes results in abnormalities or aberrations.' Because genes reside on chromosomes (R), any structural change in chromosomes disrupts gene function, causing aberrations (A)." },

  { id: 296, topic: "Mutation", q: "Which of the following correctly differentiates point mutation from frame-shift mutation?", options: ["Point mutation involves deletion of large DNA segments; frame-shift involves single base change", "Point mutation involves change in single base pair; frame-shift involves insertion or deletion of base pairs", "Both are caused by the same mechanism", "Point mutation occurs in RNA; frame-shift occurs in DNA"], correct: 1, explanation: "NCERT clearly distinguishes: Point mutation = 'change in a single base pair of DNA' (e.g., sickle cell anaemia). Frame-shift mutation = 'Deletions and insertions of base pairs of DNA.' Option A reverses the definitions — a classic trap." },

  { id: 297, topic: "Mutation", q: "Consider the following:<br>(A) Mutation is a source of variation in DNA<br>(B) Recombination is a source of variation in DNA<br>(C) Mutation always results in beneficial changes<br>(D) Mutagens include both chemical and physical factors", options: ["(A), (B) and (D) only", "(A), (B), (C) and (D)", "(A) and (B) only", "(C) and (D) only"], correct: 0, explanation: "Statement (C) is INCORRECT — NCERT does not state that mutations are always beneficial. In fact, many mutations cause disorders (e.g., sickle cell anaemia, chromosomal aberrations in cancer). Statements A, B, and D are all correct per NCERT." },

  { id: 298, topic: "Mutation", q: "<b>Assertion (A):</b> Frame-shift mutations alter the reading frame of the genetic code.<br><b>Reason (R):</b> Frame-shift mutations are caused by deletions and insertions of base pairs.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. When base pairs are deleted or inserted (R), the triplet reading frame shifts from the point of mutation onward, causing all downstream codons to be misread (A). The insertion/deletion mechanism directly causes the frame to shift." },

  { id: 299, topic: "Mutation", q: "Which of the following is <b>NOT</b> correctly matched?", options: ["Point mutation — Single base pair change", "Frame-shift mutation — Deletion/Insertion of base pairs", "Chromosomal aberration — Loss or gain of DNA segment", "Point mutation — Deletion of entire chromosome arm"], correct: 3, explanation: "Point mutation involves a change in a SINGLE base pair — NOT deletion of an entire chromosome arm. Deletion of a chromosome arm is a chromosomal aberration, not a point mutation. This distinction between small-scale (point) and large-scale (chromosomal) mutations is critical." },

  // ───── TOPIC: PEDIGREE ANALYSIS ─────
  { id: 300, topic: "Pedigree Analysis", q: "Pedigree analysis is defined as:", options: ["Analysis of chromosomal number in an organism", "Analysis of traits in several generations of a family", "Cross-pollination experiments in plants", "Study of mutations in laboratory organisms"], correct: 1, explanation: "NCERT states: 'Such an analysis of traits in a several of generations of a family is called the pedigree analysis.' It traces the inheritance pattern of a specific trait across multiple family generations." },

  { id: 301, topic: "Pedigree Analysis", q: "Pedigree analysis is used as an alternative to control crosses in humans because:", options: ["Humans have too many chromosomes", "Human generation time is too short", "Control crosses cannot be performed in humans", "Humans do not show Mendelian inheritance"], correct: 2, explanation: "NCERT states: 'Since it is evident that control crosses that can be performed in pea plant or some other organisms, are not possible in case of human beings, study of the family history about inheritance of a particular trait provides an alternative.' Ethical and practical reasons prevent controlled crosses in humans." },

  { id: 302, topic: "Pedigree Analysis", q: "In pedigree analysis, the inheritance of a particular trait is represented as:", options: ["A Punnett square", "A family tree over generations", "A bar graph of trait frequency", "A chromosome map"], correct: 1, explanation: "NCERT states: 'In the pedigree analysis the inheritance of a particular trait is represented in the family tree over generations.' The family tree (pedigree chart) uses standardised symbols to show inheritance patterns across generations." },

  { id: 303, topic: "Pedigree Analysis", q: "Pedigree study in human genetics is utilised to trace:<br>(i) Inheritance of a specific trait<br>(ii) Inheritance of an abnormality<br>(iii) Inheritance of a disease<br>Select the correct option:", options: ["(i) only", "(i) and (iii) only", "(i), (ii) and (iii)", "(ii) and (iii) only"], correct: 2, explanation: "NCERT states: 'pedigree study provides a strong tool, which is utilised to trace the inheritance of a specific trait, abnormality or disease.' All three — traits, abnormalities, AND diseases — can be traced using pedigree analysis." },

  { id: 304, topic: "Pedigree Analysis", q: "<b>Assertion (A):</b> Pedigree analysis provides an alternative to controlled genetic crosses in humans.<br><b>Reason (R):</b> Ethical and practical considerations do not allow controlled matings in human beings.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states control crosses 'are not possible in case of human beings' and pedigree analysis 'provides an alternative.' The reason control crosses aren't possible (R) is precisely why pedigree analysis serves as an alternative method (A)." },

  { id: 305, topic: "Pedigree Analysis", q: "The idea that disorders are inherited has been:", options: ["A recent discovery after DNA sequencing", "Prevailing in human society since long", "Known only after Mendel's rediscovery in 1900", "Discovered by Morgan through Drosophila studies"], correct: 1, explanation: "NCERT states: 'The idea that disorders are inherited has been prevailing in the human society since long. This was based on the heritability of certain characteristic features in families.' This understanding preceded formal genetic studies." },

  { id: 306, topic: "Pedigree Analysis", q: "The practice of analysing inheritance patterns of traits in humans began after:", options: ["Darwin's theory of evolution", "Discovery of chromosomes", "Rediscovery of Mendel's work", "Discovery of DNA structure"], correct: 2, explanation: "NCERT states: 'After the rediscovery of Mendel's work the practice of analysing inheritance pattern of traits in human beings began.' The rediscovery in 1900 by de Vries, Correns, and von Tschermak prompted systematic pedigree analysis." },

  { id: 307, topic: "Pedigree Analysis", q: "Select the <b>incorrect</b> statement about pedigree analysis:", options: ["It traces inheritance of traits across family generations", "It is used because control crosses are not possible in humans", "It can only trace physical traits, not genetic disorders", "It represents inheritance in a family tree format"], correct: 2, explanation: "Pedigree analysis can trace specific traits, ABNORMALITIES, and DISEASES — not just physical traits. NCERT explicitly states it is used to trace 'a specific trait, abnormality or disease.' Option C incorrectly limits its scope." },

  // ───── TOPIC: MUTATION AND PEDIGREE ANALYSIS ─────
  { id: 308, topic: "Mutation and Pedigree Analysis", q: "DNA is described as the carrier of genetic information that is transmitted from one generation to the other:", options: ["With frequent changes and alterations", "Without any change or alteration normally", "Only through maternal inheritance", "Only through sex chromosomes"], correct: 1, explanation: "NCERT states: 'DNA is the carrier of genetic information. It is hence transmitted from one generation to the other without any change or alteration. However, changes or alteration do take place occasionally.' Normally no changes; OCCASIONALLY mutations occur." },

  { id: 309, topic: "Mutation and Pedigree Analysis", q: "A number of disorders in human beings are associated with:", options: ["Inheritance of normal, unchanged genes only", "Environmental factors exclusively", "Inheritance of changed or altered genes or chromosomes", "Viral infections only"], correct: 2, explanation: "NCERT states: 'A number of disorders in human beings have been found to be associated with the inheritance of changed or altered genes or chromosomes.' Both gene mutations and chromosomal aberrations can cause genetic disorders." },

  { id: 310, topic: "Pedigree Analysis", q: "<b>Assertion (A):</b> Every feature in an organism is controlled by one or the other gene located on DNA present in chromosomes.<br><b>Reason (R):</b> Alterations in genetic material (mutations) can lead to disorders that are inheritable.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 1, explanation: "Both A and R are true statements from NCERT. However, R does not directly explain A. A states that genes control features (a statement about normal gene function). R states that mutations can cause inheritable disorders (about abnormal gene changes). These are related but R doesn't explain WHY genes control features." },

  // ───── TOPIC: MENDELIAN DISORDERS ─────
  { id: 311, topic: "Mendelian Disorders", q: "Mendelian disorders are mainly determined by:", options: ["Alteration in multiple chromosomes simultaneously", "Change in the number of chromosomes", "Alteration or mutation in a single gene", "Environmental factors alone"], correct: 2, explanation: "NCERT states: 'Mendelian disorders are mainly determined by alteration or mutation in the single gene.' They follow Mendelian inheritance patterns and can be traced by pedigree analysis. Chromosomal number changes cause chromosomal disorders, not Mendelian disorders." },

  { id: 312, topic: "Mendelian Disorders", q: "Which of the following is <b>NOT</b> a Mendelian disorder?", options: ["Haemophilia", "Sickle-cell anaemia", "Down syndrome", "Phenylketonuria"], correct: 2, explanation: "Down syndrome is a CHROMOSOMAL disorder (trisomy 21), not a Mendelian disorder. NCERT lists Haemophilia, Cystic fibrosis, Sickle-cell anaemia, Colour blindness, PKU, and Thalassemia as common Mendelian disorders. Mendelian disorders involve single gene mutations." },

  { id: 313, topic: "Mendelian Disorders", q: "Colour blindness is a:", options: ["Sex-linked dominant disorder", "Autosomal recessive disorder", "Sex-linked recessive disorder", "Autosomal dominant disorder"], correct: 2, explanation: "NCERT states: 'It is a sex-linked recessive disorder due to defect in either red or green cone of eye.' The genes are located on the X chromosome, making it sex-linked, and the trait is recessive — requiring both X chromosomes to carry the mutant allele for a female to be affected." },

  { id: 314, topic: "Mendelian Disorders", q: "Colour blindness results in failure to discriminate between:", options: ["Blue and yellow colours", "Red and green colours", "Black and white colours", "All colours"], correct: 1, explanation: "NCERT states it results in 'failure to discriminate between red and green colour.' This is because the defect is in 'either red or green cone of eye.' This is specifically red-green colour blindness." },

  { id: 315, topic: "Mendelian Disorders", q: "The incidence of colour blindness is about <b>8 per cent</b> in males and <b>0.4 per cent</b> in females because:", options: ["The gene is on the Y chromosome, absent in females", "Males have only one X chromosome so a single recessive allele causes the disorder", "Females cannot inherit the gene from their fathers", "The gene is autosomal but expressed only in males"], correct: 1, explanation: "NCERT states: 'This is because the genes that lead to red-green colour blindness are on the X chromosome. Males have only one X chromosome and females have two.' Males need only one mutant X allele to be affected, but females need BOTH X chromosomes to carry the allele — making it much rarer in females." },

  { id: 316, topic: "Mendelian Disorders", q: "A daughter will be colour blind only if:", options: ["Her father is colour blind", "Her mother is a carrier", "Her mother is a carrier and her father is colour blind", "Either parent is colour blind"], correct: 2, explanation: "NCERT states: 'A daughter will not normally be colour blind, unless her mother is a carrier and her father is colour blind.' The daughter must receive one mutant X from carrier mother AND one mutant X from colour blind father to be homozygous recessive (XᶜXᶜ)." },

  { id: 317, topic: "Mendelian Disorders", q: "The son of a carrier woman for colour blindness has what per cent chance of being colour blind?", options: ["25 per cent", "50 per cent", "75 per cent", "100 per cent"], correct: 1, explanation: "NCERT states: 'The son of a woman who carries the gene has a 50 per cent chance of being colour blind.' Carrier mother (XᶜX) produces X and Xᶜ eggs in equal proportion. Sons receiving Xᶜ will be colour blind; sons receiving X will be normal — 50% chance." },

  { id: 318, topic: "Mendelian Disorders", q: "<b>Assertion (A):</b> A carrier female for colour blindness is not herself colour blind.<br><b>Reason (R):</b> The gene for colour blindness is recessive and its effect is suppressed by the matching dominant normal gene.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states: 'The mother is not herself colour blind because the gene is recessive. That means that its effect is suppressed by her matching dominant normal gene.' The presence of one normal dominant allele on the other X chromosome (R) masks the recessive colour blind allele in the carrier female (A)." },

  { id: 319, topic: "Mendelian Disorders", q: "Haemophilia is characterised by:", options: ["Inability to produce red blood cells", "Non-stop bleeding due to affected clotting protein", "Excess production of white blood cells", "Deficiency of haemoglobin"], correct: 1, explanation: "NCERT states: 'a single protein that is a part of the cascade of proteins involved in the clotting of blood is affected. Due to this, in an affected individual a simple cut will result in non-stop bleeding.' Haemophilia affects blood CLOTTING, not RBC production or haemoglobin." },

  { id: 320, topic: "Mendelian Disorders", q: "The possibility of a female becoming haemophilic is extremely rare because:", options: ["The gene is on the Y chromosome", "Females cannot carry the haemophilia gene", "Mother must be at least carrier and father must be haemophilic, which is unviable", "Haemophilia affects only blood clotting proteins found in males"], correct: 2, explanation: "NCERT states: 'The possibility of a female becoming a haemophilic is extremely rare because mother of such a female has to be at least carrier and the father should be haemophilic (unviable in the later stage of life).' The father being haemophilic is usually lethal, making this combination practically impossible." },

  { id: 321, topic: "Mendelian Disorders", q: "The family pedigree showing haemophilic descendants is famously associated with:", options: ["Queen Elizabeth I", "Queen Victoria", "Queen Mary", "Queen Anne"], correct: 1, explanation: "NCERT states: 'The family pedigree of Queen Victoria shows a number of haemophilic descendents as she was a carrier of the disease.' This is one of the most famous examples of sex-linked inheritance in human genetics." },

  { id: 322, topic: "Mendelian Disorders", q: "Sickle-cell anaemia is:", options: ["A sex-linked dominant trait", "An autosome-linked recessive trait", "A sex-linked recessive trait", "An autosome-linked dominant trait"], correct: 1, explanation: "NCERT states: 'This is an autosome linked recessive trait that can be transmitted from parents to the offspring when both the partners are carrier for the gene.' Students frequently confuse this with sex-linked disorders — sickle cell is AUTOSOMAL, not sex-linked." },

  { id: 323, topic: "Mendelian Disorders", q: "In sickle-cell anaemia, the amino acid substitution is:", options: ["Valine replaced by Glutamic acid at 6th position", "Glutamic acid replaced by Valine at 6th position of β-globin chain", "Glutamic acid replaced by Valine at 11th position of α-globin chain", "Valine replaced by Leucine at 6th position of β-globin chain"], correct: 1, explanation: "NCERT states: 'The defect is caused by the substitution of Glutamic acid (Glu) by Valine (Val) at the sixth position of the beta globin chain of the haemoglobin molecule.' Glu→Val at 6th position of β-globin (not α-globin). This precise detail is extremely frequently tested." },

  { id: 324, topic: "Mendelian Disorders", q: "The single base substitution in sickle-cell anaemia at the sixth codon of β-globin gene is:", options: ["GAG to GAA", "GUG to GAG", "GAG to GUG", "GAG to GTG"], correct: 2, explanation: "NCERT states: 'the single base substitution at the sixth codon of the beta globin gene from GAG to GUG.' GAG (Glutamic acid) → GUG (Valine). Note: this is at the mRNA codon level (U not T). Option D uses DNA notation (GTG) — NCERT specifically uses GUG." },

  { id: 325, topic: "Mendelian Disorders", q: "In sickle-cell anaemia, the mutant haemoglobin molecule undergoes polymerisation under:", options: ["High oxygen tension", "Low oxygen tension", "Normal oxygen tension", "High carbon dioxide tension only"], correct: 1, explanation: "NCERT states: 'The mutant haemoglobin molecule undergoes polymerisation under low oxygen tension causing the change in the shape of the RBC.' Low O₂ conditions cause HbS molecules to aggregate and polymerise, deforming the RBC into sickle shape." },

  { id: 326, topic: "Mendelian Disorders", q: "In sickle-cell anaemia, the shape of RBC changes from:", options: ["Sickle to biconcave disc", "Spherical to biconcave disc", "Biconcave disc to elongated sickle-like structure", "Biconcave disc to spherical shape"], correct: 2, explanation: "NCERT states the polymerisation causes 'the change in the shape of the RBC from biconcave disc to elongated sickle like structure.' Normal RBCs are biconcave discs; mutant HbS causes them to become sickle-shaped under low oxygen." },

  { id: 327, topic: "Mendelian Disorders", q: "In sickle-cell anaemia, which of the following genotypes shows the diseased phenotype?", options: ["Hb<sup>A</sup>Hb<sup>A</sup> (homozygous normal)", "Hb<sup>A</sup>Hb<sup>S</sup> (heterozygous)", "Hb<sup>S</sup>Hb<sup>S</sup> (homozygous mutant)", "Both Hb<sup>A</sup>Hb<sup>S</sup> and Hb<sup>S</sup>Hb<sup>S</sup>"], correct: 2, explanation: "NCERT states: 'Out of the three possible genotypes only homozygous individuals for HbS (HbSHbS) show the diseased phenotype.' Heterozygous individuals (HbAHbS) are carriers showing sickle-cell trait but appear apparently unaffected." },

  { id: 328, topic: "Mendelian Disorders", q: "Heterozygous individuals (Hb<sup>A</sup>Hb<sup>S</sup>) for sickle-cell anaemia:", options: ["Show the full diseased phenotype", "Are completely normal with no carrier status", "Appear apparently unaffected but are carriers with sickle-cell trait", "Always die before adulthood"], correct: 2, explanation: "NCERT states: 'Heterozygous (HbAHbS) individuals appear apparently unaffected but they are carrier of the disease as there is 50 per cent probability of transmission of the mutant gene to the progeny, thus exhibiting sickle-cell trait.' They look normal but carry the mutant allele." },

  { id: 329, topic: "Mendelian Disorders", q: "<b>Assertion (A):</b> Sickle-cell anaemia can be transmitted only when both parents are carriers.<br><b>Reason (R):</b> The disease is autosome-linked recessive, requiring homozygosity (Hb<sup>S</sup>Hb<sup>S</sup>) for disease expression.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states sickle-cell anaemia 'can be transmitted from parents to the offspring when both the partners are carrier for the gene.' Since it's autosomal recessive, both parents must contribute HbS allele (R), making the child HbSHbS. If only one parent is carrier, child can be carrier but not diseased." },

  { id: 330, topic: "Mendelian Disorders", q: "Phenylketonuria is caused by the lack of an enzyme that converts:", options: ["Tyrosine into phenylalanine", "Phenylalanine into tyrosine", "Phenylalanine into phenylpyruvic acid", "Tyrosine into melanin"], correct: 1, explanation: "NCERT states: 'The affected individual lacks an enzyme that converts the amino acid phenylalanine into tyrosine.' The enzyme is phenylalanine hydroxylase. When absent, phenylalanine accumulates and is converted to phenylpyruvic acid — but this conversion is NOT the normal enzyme's function." },

  { id: 331, topic: "Mendelian Disorders", q: "In phenylketonuria, the accumulated phenylalanine is converted into:", options: ["Tyrosine and melanin", "Phenylpyruvic acid and other derivatives", "Tryptophan and serotonin", "Glutamic acid and valine"], correct: 1, explanation: "NCERT states: 'phenylalanine is accumulated and converted into phenylpyruvic acid and other derivatives.' These derivatives accumulate in the brain causing mental retardation and are excreted through urine due to poor kidney absorption." },

  { id: 332, topic: "Mendelian Disorders", q: "In PKU, mental retardation is caused by:", options: ["Accumulation of tyrosine in the brain", "Accumulation of phenylpyruvic acid and derivatives in the brain", "Deficiency of melanin in the brain", "Excess production of phenylalanine hydroxylase"], correct: 1, explanation: "NCERT states: 'Accumulation of these in brain results in mental retardation.' The 'these' refers to phenylpyruvic acid and other derivatives of phenylalanine. The excess phenylalanine derivatives damage brain tissue." },

  { id: 333, topic: "Mendelian Disorders", q: "Phenylpyruvic acid and its derivatives are excreted through urine in PKU patients because of:", options: ["Excess production in the liver", "Overactive kidneys", "Poor absorption by kidney", "Active secretion by kidney tubules"], correct: 2, explanation: "NCERT states: 'These are also excreted through urine because of its poor absorption by kidney.' The kidney fails to reabsorb these accumulated metabolites, so they appear in the urine — a diagnostic feature of PKU." },

  { id: 334, topic: "Mendelian Disorders", q: "Thalassemia is caused by:", options: ["Qualitative defect producing incorrectly functioning globin", "Quantitative defect causing reduced rate of synthesis of globin chains", "Complete absence of all globin chains", "Excess production of haemoglobin"], correct: 1, explanation: "NCERT states: 'The defect could be due to either mutation or deletion which ultimately results in reduced rate of synthesis of one of the globin chains.' Thalassemia is specifically described as a QUANTITATIVE problem — too few globin molecules produced." },

  { id: 335, topic: "Mendelian Disorders", q: "Which of the following correctly differentiates thalassemia from sickle-cell anaemia?", options: ["Thalassemia is qualitative; sickle-cell is quantitative", "Thalassemia is quantitative (too few globin molecules); sickle-cell is qualitative (incorrectly functioning globin)", "Both are quantitative problems", "Both are qualitative problems"], correct: 1, explanation: "NCERT explicitly states: 'Thalassemia differs from sickle-cell anaemia in that the former is a quantitative problem of synthesising too few globin molecules while the latter is a qualitative problem of synthesising an incorrectly functioning globin.' This distinction is one of the most important NEET facts." },

  { id: 336, topic: "Mendelian Disorders", q: "α-Thalassemia is controlled by two closely linked genes on:", options: ["Chromosome 11", "Chromosome 16", "X chromosome", "Chromosome 21"], correct: 1, explanation: "NCERT states: 'α Thalassemia is controlled by two closely linked genes HBA1 and HBA2 on chromosome 16 of each parent.' β-Thalassemia is controlled by gene HBB on chromosome 11. Students frequently mix up chromosomes 16 and 11." },

  { id: 337, topic: "Mendelian Disorders", q: "β-Thalassemia is controlled by:", options: ["Two closely linked genes HBA1 and HBA2 on chromosome 16", "A single gene HBB on chromosome 11", "A single gene on the X chromosome", "Multiple genes on chromosome 16"], correct: 1, explanation: "NCERT states: 'β Thalassemia is controlled by a single gene HBB on chromosome 11 of each parent and occurs due to mutation of one or both the genes.' α-Thalassemia = chromosome 16 (two genes); β-Thalassemia = chromosome 11 (one gene)." },

  { id: 338, topic: "Mendelian Disorders", q: "In α-Thalassemia, the severity of the disease depends on:", options: ["The type of amino acid substitution", "The number of genes affected out of four", "The presence of Y chromosome", "Environmental factors only"], correct: 1, explanation: "NCERT states: 'it is observed due to mutation or deletion of one or more of the four genes. The more genes affected, the less alpha globin molecules produced.' Since there are 2 genes per chromosome 16 (× 2 parents = 4 copies), severity correlates with number of affected genes." },

  { id: 339, topic: "Mendelian Disorders", q: "Consider the following:<br>(A) Colour blindness — Sex-linked recessive — X chromosome<br>(B) Sickle-cell anaemia — Autosome-linked recessive — β-globin gene<br>(C) Haemophilia — Autosome-linked dominant — Clotting protein<br>(D) PKU — Autosomal recessive — Phenylalanine hydroxylase<br>Which are correctly described?", options: ["(A), (B) and (D) only", "(A), (B), (C) and (D)", "(A) and (C) only", "(B) and (D) only"], correct: 0, explanation: "Statement (C) is INCORRECT — Haemophilia is SEX-LINKED recessive (not autosome-linked dominant). It is X-linked and recessive. Statements A (colour blindness = sex-linked recessive), B (sickle cell = autosomal recessive, β-globin), and D (PKU = autosomal recessive, phenylalanine hydroxylase) are all correct." },

  { id: 340, topic: "Mendelian Disorders", q: "<b>Assertion (A):</b> Thalassemia can result from either mutation or deletion.<br><b>Reason (R):</b> Both mutation and deletion can reduce the rate of synthesis of globin chains.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT states: 'The defect could be due to either mutation or deletion which ultimately results in reduced rate of synthesis of one of the globin chains.' Both mutation and deletion (R) can impair globin gene function, leading to reduced synthesis (explaining A)." },

  // ───── TOPIC: CHROMOSOMAL DISORDERS ─────
  { id: 341, topic: "Chromosomal Disorders", q: "Chromosomal disorders are caused due to:<br>(i) Absence of one or more chromosomes<br>(ii) Excess of one or more chromosomes<br>(iii) Abnormal arrangement of chromosomes<br>Select the correct option:", options: ["(i) only", "(i) and (ii) only", "(i), (ii) and (iii)", "(ii) and (iii) only"], correct: 2, explanation: "NCERT states: 'The chromosomal disorders are caused due to absence or excess or abnormal arrangement of one or more chromosomes.' All three mechanisms — absence, excess, and abnormal arrangement — can cause chromosomal disorders." },

  { id: 342, topic: "Chromosomal Disorders", q: "Aneuploidy is caused by:", options: ["Failure of cytokinesis after telophase", "Failure of segregation of chromatids during cell division", "Point mutation in a single gene", "Deletion of a base pair in DNA"], correct: 1, explanation: "NCERT states: 'Failure of segregation of chromatids during cell division cycle results in the gain or loss of a chromosome(s), called aneuploidy.' Failure of cytokinesis after telophase causes polyploidy (not aneuploidy). This is the most important distinction." },

  { id: 343, topic: "Chromosomal Disorders", q: "Polyploidy is caused by:", options: ["Failure of segregation of chromatids during cell division", "Mutation in a single base pair", "Failure of cytokinesis after telophase stage of cell division", "Deletion of an entire chromosome"], correct: 2, explanation: "NCERT states: 'Failure of cytokinesis after telophase stage of cell division results in an increase in a whole set of chromosomes in an organism and, this phenomenon is known as polyploidy.' Aneuploidy = failure of chromatid segregation; Polyploidy = failure of cytokinesis after telophase." },

  { id: 344, topic: "Chromosomal Disorders", q: "Polyploidy is a condition that is often seen in:", options: ["Humans", "Birds", "Plants", "Insects"], correct: 2, explanation: "NCERT states: 'This condition is often seen in plants.' Polyploidy (increase in whole set of chromosomes) is common in plants and is often commercially exploited, but it is rare and usually lethal in animals including humans." },

  { id: 345, topic: "Chromosomal Disorders", q: "An individual having an additional copy of a chromosome is said to have:", options: ["Monosomy", "Trisomy", "Polyploidy", "Haploidy"], correct: 1, explanation: "NCERT states: 'an additional copy of a chromosome may be included in an individual... These situations are known as trisomy.' Trisomy = three copies of a particular chromosome (2n + 1). Monosomy = one copy missing (2n - 1). Polyploidy = entire set multiplied." },

  { id: 346, topic: "Chromosomal Disorders", q: "An individual lacking one of any pair of chromosomes has the condition known as:", options: ["Trisomy", "Polyploidy", "Monosomy", "Aneuploidy only"], correct: 2, explanation: "NCERT states: 'an individual may lack one of any one pair of chromosomes. These situations are known as... monosomy of a chromosome, respectively.' Monosomy = 2n - 1. Turner's syndrome (45, XO) is an example of monosomy." },

  { id: 347, topic: "Chromosomal Disorders", q: "Down's syndrome is caused by:", options: ["Monosomy of chromosome 21", "Trisomy of chromosome 21", "Trisomy of chromosome 18", "Absence of one X chromosome"], correct: 1, explanation: "NCERT states: 'The cause of this genetic disorder is the presence of an additional copy of the chromosome number 21 (trisomy of 21).' Down's syndrome = trisomy 21 (three copies of chromosome 21). Students sometimes confuse chromosome 21 with other chromosomes." },

  { id: 348, topic: "Chromosomal Disorders", q: "Down's syndrome was first described by:", options: ["Gregor Mendel in 1865", "Langdon Down in 1866", "T.H. Morgan in 1910", "Henking in 1891"], correct: 1, explanation: "NCERT states: 'This disorder was first described by Langdon Down (1866).' The year 1866 is just one year after Mendel's publication (1865). Students should not confuse these two historical dates." },

  { id: 349, topic: "Chromosomal Disorders", q: "Which of the following is <b>NOT</b> a feature of Down's syndrome?", options: ["Short stature with small round head", "Furrowed tongue and partially open mouth", "Broad palm with characteristic palm crease", "Overall feminine development with gynaecomastia"], correct: 3, explanation: "Gynaecomastia (breast development in males) is a feature of KLINEFELTER'S syndrome (XXY), NOT Down's syndrome. Down's syndrome features include: short stature, small round head, furrowed tongue, partially open mouth, broad palm with characteristic palm crease, and retarded physical/psychomotor/mental development." },

  { id: 350, topic: "Chromosomal Disorders", q: "Consider the following features of Down's syndrome:<br>(i) Short stature<br>(ii) Furrowed tongue<br>(iii) Broad palm with characteristic palm crease<br>(iv) Physical, psychomotor and mental development is retarded<br>Which are correct?", options: ["(i) and (ii) only", "(i), (ii) and (iii) only", "(i), (iii) and (iv) only", "(i), (ii), (iii) and (iv)"], correct: 3, explanation: "All four features are correctly listed for Down's syndrome per NCERT. NCERT states the affected individual is 'short statured with small round head, furrowed tongue and partially open mouth. Palm is broad with characteristic palm crease. Physical, psychomotor and mental development is retarded.'" },

  { id: 351, topic: "Chromosomal Disorders", q: "Klinefelter's syndrome has the karyotype:", options: ["45, XO", "46, XY", "47, XXY", "47, XXX"], correct: 2, explanation: "NCERT states: 'This genetic disorder is also caused due to the presence of an additional copy of X chromosome resulting into a karyotype of 47, XXY.' Klinefelter's = 47 chromosomes (44 autosomes + XXY). 45,XO = Turner's; 46,XY = normal male." },

  { id: 352, topic: "Chromosomal Disorders", q: "An individual with Klinefelter's syndrome shows:", options: ["Overall feminine development only", "Overall masculine development with feminine development (gynaecomastia)", "Overall normal development with no abnormalities", "Overall masculine development with no feminine features"], correct: 1, explanation: "NCERT states: 'Such an individual has overall masculine development, however, the feminine development (development of breast, i.e., Gynaecomastia) is also expressed.' Both masculine AND feminine features are present — masculine is overall, with gynaecomastia as the feminine expression." },

  { id: 353, topic: "Chromosomal Disorders", q: "Individuals with Klinefelter's syndrome are:", options: ["Fertile males", "Fertile females", "Sterile", "Capable of reproduction with medical assistance"], correct: 2, explanation: "NCERT states: 'Such individuals are sterile.' Klinefelter's (XXY) individuals are sterile males. Similarly, Turner's (XO) individuals are also sterile females. Sterility is a common feature of both these chromosomal disorders." },

  { id: 354, topic: "Chromosomal Disorders", q: "Turner's syndrome is caused by:", options: ["Presence of an additional X chromosome (XXX)", "Presence of an additional copy of chromosome 21", "Absence of one X chromosome (45, XO)", "Presence of an additional Y chromosome (XYY)"], correct: 2, explanation: "NCERT states: 'Such a disorder is caused due to the absence of one of the X chromosomes, i.e., 45 with XO.' Turner's syndrome is an example of monosomy — one sex chromosome is missing. Total chromosomes = 45 (not 44 or 46)." },

  { id: 355, topic: "Chromosomal Disorders", q: "Which of the following features are seen in Turner's syndrome?<br>(i) Sterility<br>(ii) Rudimentary ovaries<br>(iii) Lack of secondary sexual characters<br>(iv) Gynaecomastia", options: ["(i), (ii) and (iii) only", "(i), (ii), (iii) and (iv)", "(i) and (ii) only", "(iv) only"], correct: 0, explanation: "Turner's syndrome features include sterility, rudimentary ovaries, and lack of other secondary sexual characters. Gynaecomastia (iv) is a feature of KLINEFELTER'S syndrome, NOT Turner's. This mix-up between Turner's and Klinefelter's symptoms is a very common NEET trap." },

  { id: 356, topic: "Chromosomal Disorders", q: "<b>Assertion (A):</b> Both Turner's syndrome and Klinefelter's syndrome result in sterility.<br><b>Reason (R):</b> Both involve abnormalities in the number of sex chromosomes.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. Turner's (XO) and Klinefelter's (XXY) both result in sterility (A). Both involve abnormal sex chromosome numbers — Turner's has one missing X, Klinefelter's has an extra X (R). The sex chromosome abnormality is what disrupts normal reproductive development, causing sterility." },

  { id: 357, topic: "Chromosomal Disorders", q: "Which of the following is correctly matched?", options: ["Down's syndrome — 45, XO — Monosomy", "Turner's syndrome — 47, XXY — Trisomy", "Klinefelter's syndrome — 47, XXY — Additional X chromosome", "Down's syndrome — 47, XX — Trisomy of chromosome 22"], correct: 2, explanation: "Klinefelter's = 47, XXY = additional X chromosome ✓. Down's = trisomy of chromosome 21 (not 22), with 47 chromosomes (not 45). Turner's = 45, XO (not 47, XXY). These are the three most confused karyotypes in NEET." },

  { id: 358, topic: "Chromosomal Disorders", q: "The total number of chromosomes in an individual with Down's syndrome is:", options: ["45", "46", "47", "48"], correct: 2, explanation: "Down's syndrome = trisomy 21 = one extra copy of chromosome 21. Normal = 46 chromosomes + 1 extra = 47 total. NCERT summary confirms: 'the total number of chromosome becomes 47.' Turner's has 45; normal has 46; Down's and Klinefelter's both have 47." },

  { id: 359, topic: "Chromosomal Disorders", q: "The total number of chromosomes in Turner's syndrome is:", options: ["44", "45", "46", "47"], correct: 1, explanation: "NCERT states Turner's syndrome has '45 with XO.' One X chromosome is missing from the normal female complement of XX. So 46 - 1 = 45. Students sometimes incorrectly write 44 (forgetting that the remaining X counts)." },

  { id: 360, topic: "Chromosomal Disorders", q: "Select the <b>incorrect</b> statement:", options: ["Aneuploidy involves gain or loss of a chromosome", "Polyploidy involves increase in whole set of chromosomes", "Polyploidy results from failure of segregation of chromatids", "Aneuploidy results from failure of segregation of chromatids"], correct: 2, explanation: "Polyploidy results from failure of CYTOKINESIS AFTER TELOPHASE (not failure of chromatid segregation). Failure of chromatid segregation causes ANEUPLOIDY. This is the most critical distinction: Aneuploidy = segregation failure; Polyploidy = cytokinesis failure." },

  { id: 361, topic: "Chromosomal Disorders", q: "<b>Assertion (A):</b> Down's syndrome and Klinefelter's syndrome both have 47 chromosomes.<br><b>Reason (R):</b> Both are caused by trisomy of the same chromosome.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 2, explanation: "Assertion is TRUE — both have 47 chromosomes. Reason is FALSE — they are NOT caused by trisomy of the same chromosome. Down's = trisomy of chromosome 21 (autosome). Klinefelter's = additional X sex chromosome (XXY). Different chromosomes are involved." },

  { id: 362, topic: "Chromosomal Disorders", q: "Gynaecomastia is associated with which chromosomal disorder?", options: ["Down's syndrome", "Turner's syndrome", "Klinefelter's syndrome", "Sickle-cell anaemia"], correct: 2, explanation: "NCERT states about Klinefelter's syndrome: 'the feminine development (development of breast, i.e., Gynaecomastia) is also expressed.' Gynaecomastia is exclusive to Klinefelter's among the disorders listed. It is NOT seen in Down's, Turner's, or sickle cell (which is a Mendelian disorder, not chromosomal)." },

  { id: 363, topic: "Chromosomal Disorders", q: "Which of the following correctly differentiates aneuploidy from polyploidy?", options: ["Aneuploidy = gain of whole chromosome set; Polyploidy = gain/loss of individual chromosome", "Aneuploidy = gain/loss of individual chromosome; Polyploidy = increase in whole set of chromosomes", "Both involve the same mechanism", "Aneuploidy occurs in plants only; Polyploidy occurs in animals only"], correct: 1, explanation: "Aneuploidy = gain or loss of individual chromosome(s) due to non-disjunction during cell division. Polyploidy = increase in entire set of chromosomes due to failure of cytokinesis. Option A reverses the definitions. Both can occur in plants and animals, though polyploidy is more common in plants." },

  { id: 364, topic: "Chromosomal Disorders", q: "Match the following:<br>(a) Down's syndrome — (i) 45, XO<br>(b) Turner's syndrome — (ii) 47, XXY<br>(c) Klinefelter's syndrome — (iii) Trisomy 21", options: ["a–iii, b–i, c–ii", "a–i, b–ii, c–iii", "a–ii, b–iii, c–i", "a–iii, b–ii, c–i"], correct: 0, explanation: "Down's syndrome = Trisomy 21 (a–iii). Turner's syndrome = 45, XO (b–i). Klinefelter's syndrome = 47, XXY (c–ii). This matching is one of the most commonly tested questions in NEET from this chapter." },

  { id: 365, topic: "Chromosomal Disorders", q: "Turner's syndrome affects:", options: ["Males only", "Females only", "Both males and females equally", "Only individuals with XY karyotype"], correct: 1, explanation: "NCERT states: 'Such females are sterile as ovaries are rudimentary.' Turner's syndrome (45, XO) specifically affects females. The missing sex chromosome is one X from the normal female XX complement. Males cannot have Turner's syndrome as they already have only one X." },

  { id: 366, topic: "Chromosomal Disorders", q: "These chromosomal disorders can be easily studied by analysis of:", options: ["Pedigree charts", "Punnett squares", "Karyotypes", "Genetic maps"], correct: 2, explanation: "NCERT summary states: 'These can be easily studied by analysis of Karyotypes.' Karyotype analysis involves arranging chromosomes by size, shape, and number — making it easy to detect extra or missing chromosomes. Pedigree charts are used for Mendelian disorders." },

  // ───── TOPIC: SUMMARY - COMPREHENSIVE ─────
  { id: 367, topic: "Summary - Comprehensive", q: "Consider the following:<br>(A) Law of Dominance explains expression in heterozygous condition<br>(B) Law of Segregation explains separation of alleles during gamete formation<br>(C) Law of Independent Assortment applies to linked genes<br>(D) Punnett Square represents different gamete combinations<br>Which statements are correct?", options: ["(A), (B) and (D) only", "(A), (B), (C) and (D)", "(A) and (B) only", "(C) and (D) only"], correct: 0, explanation: "Statement (C) is INCORRECT — Law of Independent Assortment does NOT hold true for linked genes. NCERT summary states: 'Mendel's law of independent assortment does not hold true for the genes that were located on the same chromosomes.' Statements A, B, and D are correct." },

  { id: 368, topic: "Summary - Comprehensive", q: "According to the NCERT summary, which of the following is correct about linked genes?", options: ["Closely located genes assort independently", "Distantly located genes assort together due to linkage", "Closely located genes assort together, and distantly located genes assort independently due to recombination", "All linked genes always assort together regardless of distance"], correct: 2, explanation: "NCERT summary states: 'Closely located genes assorted together, and distantly located genes, due to recombination, assorted independently.' The distance between genes determines the strength of linkage — closer = tighter linkage, farther = more recombination and independent assortment." },

  { id: 369, topic: "Summary - Comprehensive", q: "<b>Assertion (A):</b> Characters never blend in heterozygous condition.<br><b>Reason (R):</b> A recessive character not expressed in heterozygous condition can be expressed again when it becomes homozygous.", options: ["Both A and R are true and R is the correct explanation of A", "Both A and R are true but R is NOT the correct explanation of A", "A is true but R is false", "A is false but R is true"], correct: 0, explanation: "Both are true. NCERT summary states: 'The characters never blend in heterozygous condition' and 'A recessive character that was not expressed in heterozygous condition may be expressed again when it becomes homozygous.' The reappearance of recessive traits unchanged in F2 (R) proves that blending did not occur in the heterozygote (A)." },

  { id: 370, topic: "Summary - Comprehensive", q: "Which of the following pairs of chromosomal disorders have the <b>same</b> total chromosome number?", options: ["Down's syndrome and Turner's syndrome", "Turner's syndrome and Klinefelter's syndrome", "Down's syndrome and Klinefelter's syndrome", "All three have the same chromosome number"], correct: 2, explanation: "Down's syndrome (trisomy 21) = 47 chromosomes. Klinefelter's syndrome (XXY) = 47 chromosomes. Turner's syndrome (XO) = 45 chromosomes. So Down's and Klinefelter's share the same total chromosome number (47)." }

];

